// Package group implements MLS Group Management according to RFC 9420 §11-12.
//
// This package provides functionality for:
//   - Group creation and joining
//   - Proposal handling (Add, Update, Remove)
//   - Commit creation and processing
//   - Welcome message handling
//   - Member management
//
// This implementation is generic and can be used for any MLS-based protocol.
package group

import (
	"bytes"
	"context"
	"crypto/ecdsa"
	"crypto/rand"
	"fmt"
	"runtime"
	"sort"
	"sync"

	"github.com/thomas-vilte/mls-go/ciphersuite"
	mlsext "github.com/thomas-vilte/mls-go/extensions"
	"github.com/thomas-vilte/mls-go/framing"
	"github.com/thomas-vilte/mls-go/internal/tls"
	"github.com/thomas-vilte/mls-go/keypackages"
	"github.com/thomas-vilte/mls-go/schedule"
	"github.com/thomas-vilte/mls-go/secrettree"
	"github.com/thomas-vilte/mls-go/treesync"
)

// GroupID uniquely identifies an MLS group
type GroupID struct {
	Value []byte
}

// NewGroupID creates a GroupID from bytes
func NewGroupID(value []byte) *GroupID {
	return &GroupID{Value: value}
}

// NewGroupIDRandom generates a random GroupID.
func NewGroupIDRandom() (*GroupID, error) {
	id := make([]byte, 16)
	if _, err := rand.Read(id); err != nil {
		return nil, fmt.Errorf("generating random group ID: %w", err)
	}
	return &GroupID{Value: id}, nil
}

// AsSlice returns the GroupID as a byte slice.
func (g *GroupID) AsSlice() []byte {
	return g.Value
}

func secureZeroBytes(b []byte) {
	if len(b) == 0 {
		return
	}
	for i := range b {
		b[i] = 0
	}
	runtime.KeepAlive(b)
}

func secureZeroSecret(s *ciphersuite.Secret) {
	if s != nil {
		s.SecureZero()
	}
}

// GroupEpoch represents the epoch number of a group.
type GroupEpoch uint64

// NewGroupEpoch creates a new epoch.
func NewGroupEpoch(epoch uint64) GroupEpoch {
	return GroupEpoch(epoch)
}

// AsUint64 returns the epoch as uint64.
func (e GroupEpoch) AsUint64() uint64 {
	return uint64(e)
}

// Increment increments the epoch.
func (e *GroupEpoch) Increment() {
	*e++
}

// Group represents an MLS group.
//
// Group is not safe for concurrent use. Callers that access the same Group from
// multiple goroutines must provide external synchronization.
type Group struct {
	groupID               *GroupID
	epoch                 GroupEpoch
	cipherSuite           ciphersuite.CipherSuite
	groupContext          *GroupContext
	ratchetTree           *treesync.RatchetTree
	ownLeafIndex          LeafNodeIndex
	epochSecrets          *schedule.EpochSecrets
	proposals             *ProposalStore
	proposalByRef         map[string]*Proposal
	pendingCommit         *StagedCommit
	confirmationTag       []byte
	interimTranscriptHash []byte
	keySchedule           *schedule.KeySchedule
	members               map[LeafNodeIndex]*Member
	state                 GroupState
	secretTree            *secrettree.Tree
	pskMu                 sync.RWMutex
	cachedPsks            map[string][]byte
	PSKStore              PSKStore
	// paddingSize controls the block size used to pad encrypted application
	// messages (RFC 9420 §14). Zero disables padding.
	paddingSize int
	// myLeafEncryptionKey is the private HPKE key of the own leaf, used for
	// decrypting path secrets in received commits (RFC 9420 §12.4.2).
	myLeafEncryptionKey []byte
	// pendingLeafKey is the new HPKE private key generated during Commit() for
	// the committer's UpdatePath. It is applied to myLeafEncryptionKey only in
	// MergeCommit so that DiscardPendingCommit can roll back without restoring.
	pendingLeafKey []byte
	// pendingUpdatePrivKey is the private HPKE key for a pending Update proposal
	// generated by SelfUpdate. RFC §12.4.3.3: the receiver must use this key
	// (not MyLeafEncryptionKey) to decrypt the UpdatePath when the Update proposal
	// is committed in a received commit.
	pendingUpdatePrivKey []byte
	// pathNodePrivKeys stores the private HPKE keys for intermediate nodes on the
	// member's direct path that they generated during their own commits. These are
	// needed when a later commit from another member includes one of these nodes in
	// a copath resolution (RFC 9420 §12.4.2).
	pathNodePrivKeys map[treesync.NodeIndex][]byte
	// lastCommittedProposals holds the proposals from the most recent commit.
	// Set by MergeCommit so that handlers (e.g. HandlePendingReInitCommit) can
	// inspect committed proposals after PendingCommit has been cleared.
	lastCommittedProposals []*Proposal
	// epochHistory caches secrets from previous epochs to allow decryption of
	// out-of-order messages that arrive after the epoch has advanced.
	// Keyed by epoch number. Limited to the last maxCachedEpochs epochs.
	epochHistory map[uint64]*epochState

	extensionHandlers *ExtensionHandlerRegistry
}

func (g *Group) setMyLeafEncryptionKey(key []byte) {
	if g == nil {
		return
	}
	secureZeroBytes(g.myLeafEncryptionKey)
	g.myLeafEncryptionKey = key
}

func (g *Group) setPathNodePrivKey(nodeIdx treesync.NodeIndex, key []byte) {
	if g == nil {
		return
	}
	if g.pathNodePrivKeys == nil {
		g.pathNodePrivKeys = make(map[treesync.NodeIndex][]byte)
	}
	secureZeroBytes(g.pathNodePrivKeys[nodeIdx])
	g.pathNodePrivKeys[nodeIdx] = key
}

func (g *Group) deletePathNodePrivKey(nodeIdx treesync.NodeIndex) {
	if g == nil || g.pathNodePrivKeys == nil {
		return
	}
	secureZeroBytes(g.pathNodePrivKeys[nodeIdx])
	delete(g.pathNodePrivKeys, nodeIdx)
}

// GroupID returns the unique identifier of the group.
func (g *Group) GroupID() *GroupID {
	if g == nil || g.groupID == nil {
		return nil
	}
	return NewGroupID(append([]byte(nil), g.groupID.AsSlice()...))
}

// Epoch returns the current epoch of the group.
func (g *Group) Epoch() GroupEpoch {
	if g == nil {
		return 0
	}
	return g.epoch
}

// CipherSuite returns the cipher suite used by the group.
func (g *Group) CipherSuite() ciphersuite.CipherSuite {
	if g == nil {
		return 0
	}
	return g.cipherSuite
}

// GroupContext returns a clone of the current group context.
func (g *Group) GroupContext() *GroupContext {
	if g == nil || g.groupContext == nil {
		return nil
	}
	return g.groupContext.Clone()
}

// OwnLeafIndex returns the leaf node index of the local member.
func (g *Group) OwnLeafIndex() LeafNodeIndex {
	if g == nil {
		return 0
	}
	return g.ownLeafIndex
}

// PaddingSize returns the padding size used for encrypted application messages.
func (g *Group) PaddingSize() int {
	if g == nil {
		return 0
	}
	return g.paddingSize
}

// SetPaddingSize sets the padding size used for encrypted application messages.
func (g *Group) SetPaddingSize(size int) {
	if g == nil {
		return
	}
	if size < 0 {
		size = 0
	}
	g.paddingSize = size
}

// ConfirmationTag returns the confirmation tag of the current epoch.
func (g *Group) ConfirmationTag() []byte {
	if g == nil {
		return nil
	}
	return append([]byte(nil), g.confirmationTag...)
}

// InterimTranscriptHash returns the interim transcript hash of the current epoch.
func (g *Group) InterimTranscriptHash() []byte {
	if g == nil {
		return nil
	}
	return append([]byte(nil), g.interimTranscriptHash...)
}

// PendingCommit returns the currently staged commit, if any.
func (g *Group) PendingCommit() *StagedCommit {
	if g == nil {
		return nil
	}
	return g.pendingCommit
}

// DiscardPendingCommit rolls back a staged commit, returning the group to
// StateOperational so it can generate a new commit.
//
// Per RFC 9420 §14: called when the Delivery Service rejects the commit or a
// conflicting commit wins the epoch. The pending proposals are preserved —
// the application should re-commit or clear them as appropriate.
func (g *Group) DiscardPendingCommit() error {
	if g.state != StatePendingCommit {
		return fmt.Errorf("%w (state=%d)", ErrNoPendingCommit, g.state)
	}
	g.pendingCommit = nil
	secureZeroBytes(g.pendingLeafKey)
	g.pendingLeafKey = nil
	g.state = StateOperational
	return nil
}

// LastCommittedProposals returns the list of proposals applied in the last commit.
func (g *Group) LastCommittedProposals() []*Proposal {
	if g == nil {
		return nil
	}
	out := make([]*Proposal, len(g.lastCommittedProposals))
	copy(out, g.lastCommittedProposals)
	return out
}

// MarshalRatchetTree serializes the group's ratchet tree.
func (g *Group) MarshalRatchetTree() []byte {
	if g == nil || g.ratchetTree == nil {
		return nil
	}
	return g.ratchetTree.MarshalTree()
}

// MarshalRatchetTreeRFC serializes the group's ratchet tree using the RFC 9420 format.
func (g *Group) MarshalRatchetTreeRFC() []byte {
	if g == nil || g.ratchetTree == nil {
		return nil
	}
	return g.ratchetTree.MarshalTreeRFC()
}

// EpochSecrets returns the current epoch's derived secrets.
func (g *Group) EpochSecrets() *schedule.EpochSecrets { return g.epochSecrets }

// SecretTree returns the current epoch's secret tree.
func (g *Group) SecretTree() *secrettree.Tree { return g.secretTree }

// CachedPsks returns a snapshot of the PSK cache (resumption PSKs and LoadPsk
// entries). The returned map is a deep copy — safe to read after the call.
func (g *Group) CachedPsks() map[string][]byte {
	g.pskMu.RLock()
	defer g.pskMu.RUnlock()
	out := make(map[string][]byte, len(g.cachedPsks))
	for k, v := range g.cachedPsks {
		out[k] = append([]byte(nil), v...)
	}
	return out
}

// Proposals returns the current proposal store.
func (g *Group) Proposals() *ProposalStore { return g.proposals }

// MyLeafEncryptionKey returns the private HPKE key bytes of the own leaf.
func (g *Group) MyLeafEncryptionKey() []byte { return g.myLeafEncryptionKey }

// StoreProposalWithRef stores a proposal with a pre-computed reference hash.
func (g *Group) StoreProposalWithRef(p *Proposal, sender LeafNodeIndex, ref []byte) {
	if g.proposalByRef == nil {
		g.proposalByRef = make(map[string]*Proposal)
	}
	g.proposalByRef[string(ref)] = p
	g.proposals.AddProposalWithRef(p, sender, ref)
}

// RegisterProposalRef associates a ProposalRef with a proposal already stored in
// g.proposals. Call this after signing a locally-created proposal so that commits
// from other actors that reference the proposal byReference can be resolved.
//
// Unlike StoreProposalWithRef, this does NOT add a new entry to g.proposals;
// it only updates the existing entry's Ref field and registers the ref in the
// lookup map.
func (g *Group) RegisterProposalRef(p *Proposal, ref []byte) {
	if g.proposalByRef == nil {
		g.proposalByRef = make(map[string]*Proposal)
	}
	g.proposalByRef[string(ref)] = p
	for i, sp := range g.proposals.Proposals {
		if sp.Proposal == p {
			g.proposals.Proposals[i].Ref = ref
			return
		}
	}
}

// FindMemberBySigKey returns the leaf index of the member whose current leaf
// node carries the given signature key bytes. Returns 0, false if not found.
func (g *Group) FindMemberBySigKey(sigKeyBytes []byte) (LeafNodeIndex, bool) {
	for leafIdx, member := range g.members {
		if !member.Active {
			continue
		}
		leaf := g.ratchetTree.GetLeaf(treesync.LeafIndex(leafIdx))
		// Signature keys in LeafNodes are public verification keys, not secret material.
		if leaf != nil && leaf.LeafData != nil && bytes.Equal(leaf.LeafData.SigKeyBytes(), sigKeyBytes) {
			return leafIdx, true
		}
	}
	return 0, false
}

// IterateMembers calls f for each entry in the members map (active or not).
func (g *Group) IterateMembers(f func(leafIdx LeafNodeIndex, m *Member)) {
	for leafIdx, m := range g.members {
		f(leafIdx, m)
	}
}

// GetTreeLeaf returns the leaf node at the given index from the ratchet tree.
func (g *Group) GetTreeLeaf(leafIdx LeafNodeIndex) *treesync.Node {
	return g.ratchetTree.GetLeaf(treesync.LeafIndex(leafIdx))
}

// RevokeProposal removes a pending proposal by its ProposalRef.
//
// This removes the proposal from both the pending proposal store and the
// proposalByRef lookup map. After revocation, commits that reference the
// proposal by ref will fail with "unknown proposal reference in commit".
//
// Returns true if the proposal was found and removed, false if not found.
func (g *Group) RevokeProposal(ref []byte) bool {
	for _, sp := range g.proposals.Proposals {
		if !bytes.Equal(sp.Ref, ref) {
			continue
		}
		if sp.Proposal != nil && sp.Proposal.Type == ProposalTypeUpdate && g.pendingUpdatePrivKey != nil && sp.Proposal.Update != nil && sp.Proposal.Update.LeafNode != nil {
			ownLeaf := g.ratchetTree.GetLeaf(treesync.LeafIndex(g.ownLeafIndex))
			if ownLeaf != nil && ownLeaf.LeafData != nil && bytes.Equal(sp.Proposal.Update.LeafNode.SignatureKeyBytes, ownLeaf.LeafData.SigKeyBytes()) {
				secureZeroBytes(g.pendingUpdatePrivKey)
				g.pendingUpdatePrivKey = nil
			}
		}
		break
	}
	if !g.proposals.RemoveByRef(ref) {
		return false
	}
	delete(g.proposalByRef, string(ref))
	return true
}

// ClearProposals discards all currently pending proposals without committing them.
func (g *Group) ClearProposals() {
	g.proposals.Clear()
	g.proposalByRef = make(map[string]*Proposal)
	secureZeroBytes(g.pendingUpdatePrivKey)
	g.pendingUpdatePrivKey = nil
}

// epochState holds the decryption and verification material for a past epoch.
type epochState struct {
	SenderDataSecret *ciphersuite.Secret
	SecretTree       *secrettree.Tree
	RatchetTree      *treesync.RatchetTree
	GroupContext     *GroupContext
	CipherSuite      ciphersuite.CipherSuite
}

// maxCachedEpochs is the number of past epochs to keep for out-of-order decryption.
const maxCachedEpochs = 5

// cacheOldEpoch saves an old epoch's decryption material into epochHistory so
// out-of-order messages from that epoch can still be decrypted and verified
// after the group advances.
func (g *Group) cacheOldEpoch(
	oldEpoch uint64,
	oldEpochSecrets *schedule.EpochSecrets,
	oldSecretTree *secrettree.Tree,
	oldRatchetTree *treesync.RatchetTree,
	oldGroupContext *GroupContext,
	oldCipherSuite ciphersuite.CipherSuite,
) {
	if oldEpochSecrets == nil {
		return
	}
	if g.epochHistory == nil {
		g.epochHistory = make(map[uint64]*epochState)
	}

	var historicalTree *treesync.RatchetTree
	if oldRatchetTree != nil {
		historicalTree = oldRatchetTree.Clone()
	}

	g.epochHistory[oldEpoch] = &epochState{
		SenderDataSecret: oldEpochSecrets.SenderDataSecret,
		SecretTree:       oldSecretTree,
		RatchetTree:      historicalTree,
		GroupContext:     oldGroupContext.Clone(),
		CipherSuite:      oldCipherSuite,
	}

	// Evict entries older than maxCachedEpochs.
	if oldEpoch >= maxCachedEpochs {
		cutoff := oldEpoch - uint64(maxCachedEpochs)
		for ep := range g.epochHistory {
			if ep <= cutoff {
				delete(g.epochHistory, ep)
			}
		}
	}
}

// NewGroup creates a new MLS group with a single member (the creator).
//
// RFC 9420 §11.1
// This is the primary entry point for a member starting a new group.
// It initializes the group state, ratchet tree, and epoch secrets.
//
// Example:
//
//	kp, kpPriv, _ := keypackages.Generate(cred, cs)
//	group, err := group.NewGroup(groupID, cs, kp, kpPriv)
func NewGroup(
	groupID *GroupID,
	cipherSuite ciphersuite.CipherSuite,
	keyPackage *keypackages.KeyPackage,
	privKeys *keypackages.KeyPackagePrivateKeys,
	opts ...GroupOption,
) (*Group, error) {
	cfg := groupConfig{}
	for _, opt := range opts {
		if opt != nil {
			opt(&cfg)
		}
	}

	groupExtensions := cloneExtensions(cfg.extensions)
	if groupExtensions == nil {
		groupExtensions = []Extension{}
	}

	// Create ratchet tree with 1 leaf
	ratchetTree := treesync.NewRatchetTree(1, cipherSuite)

	// Add our leaf
	leafCaps := toTreeSyncCapabilities(keyPackage.LeafNode.Capabilities)
	if leafCaps == nil {
		leafCaps = &treesync.LeafNodeCapabilities{}
	}
	leafData := treesync.LeafNodeData{
		EncryptionKey:   keyPackage.LeafNode.EncryptionKey, // RFC §10.1: use LeafNode.encryption_key for TreeKEM
		SignatureKey:    keyPackage.LeafNode.SignatureKey,
		SignatureKeyRaw: append([]byte(nil), keyPackage.LeafNode.SignatureKeyBytes...),
		Credential:      keyPackage.LeafNode.Credential,
		Capabilities:    leafCaps,
		Lifetime:        keyPackageToTreeSyncLifetime(keyPackage.LeafNode.Lifetime),
		LeafNodeSource:  1, // key_package
		Signature:       append([]byte(nil), keyPackage.LeafNode.Signature...),
	}

	_, _ = ratchetTree.AddLeaf(leafData)

	// Create group context — TreeHash must be set for epoch 0 so that
	// GetGroupInfo produces a GroupContext whose tree_hash matches the
	// ratchet_tree extension (RFC §12.4.3.2 / §7.4.1).
	groupContext := &GroupContext{
		Version:     keypackages.MLS10,
		GroupID:     groupID,
		Epoch:       NewGroupEpoch(0),
		CipherSuite: cipherSuite,
		Extensions:  groupExtensions,
		TreeHash:    ratchetTree.TreeHash(),
	}

	// Initialize key schedule with zeros for first epoch
	initSecret := ciphersuite.ZeroSecretCS(cipherSuite)
	keySchedule := schedule.NewKeySchedule(cipherSuite, initSecret)

	// Compute epoch secrets
	commitSecret := ciphersuite.ZeroSecretCS(cipherSuite)
	keySchedule.SetCommitSecret(commitSecret)

	groupContextBytes := groupContext.Marshal()

	_, err := keySchedule.ComputeJoinerSecret(groupContextBytes)
	if err != nil {
		return nil, fmt.Errorf("computing joiner secret: %w", err)
	}

	_, err = keySchedule.ComputePskSecret([]schedule.Psk{})
	if err != nil {
		return nil, fmt.Errorf("computing psk secret: %w", err)
	}
	_, err = keySchedule.ComputeEpochSecret(groupContextBytes)
	if err != nil {
		return nil, fmt.Errorf("computing epoch secret: %w", err)
	}

	epochSecrets, err := keySchedule.DeriveEpochSecrets()
	if err != nil {
		return nil, fmt.Errorf("deriving epoch secrets: %w", err)
	}

	// Create group
	group := &Group{
		groupID:       groupID,
		epoch:         NewGroupEpoch(0),
		cipherSuite:   cipherSuite,
		groupContext:  groupContext,
		ratchetTree:   ratchetTree,
		ownLeafIndex:  NewLeafNodeIndex(0),
		epochSecrets:  epochSecrets,
		proposals:     NewProposalStore(),
		proposalByRef: make(map[string]*Proposal),
		keySchedule:   keySchedule,
		// RFC 9420 §6.2: for the initial epoch, interim_transcript_hash =
		// Hash(confirmed_transcript_hash || VL(confirmation_tag)) where both
		// inputs are empty → Hash([0x00]). Must match what external parties
		// derive from GroupInfo (which also has empty CTH and empty confirmation_tag).
		interimTranscriptHash: schedule.ComputeInterimTranscriptHash(cipherSuite, nil, nil),
		members:               make(map[LeafNodeIndex]*Member),
		state:                 StateOperational,
		cachedPsks:            make(map[string][]byte),
		PSKStore:              cfg.pskStore,
		paddingSize:           cfg.paddingSize,
		extensionHandlers:     cfg.extensionHandlers,
	}

	// Initialize secret tree
	group.secretTree, err = secrettree.NewTree(epochSecrets.EncryptionSecret, 1, group.cipherSuite)
	if err != nil {
		return nil, fmt.Errorf("initializing secret tree: %w", err)
	}

	// Store our leaf encryption private key for TreeKEM decryption (RFC §10.1)
	if privKeys != nil && privKeys.EncryptionKey != nil {
		group.setMyLeafEncryptionKey(privKeys.EncryptionKey.Bytes())
	}

	// Add ourselves as a member
	group.members[NewLeafNodeIndex(0)] = &Member{
		LeafIndex:  NewLeafNodeIndex(0),
		KeyPackage: keyPackage,
		Credential: keyPackage.LeafNode.Credential,
		Active:     true,
	}

	return group, nil
}

// NewGroupWithExtensions creates a new group with the given GroupContext extensions.
// Identical to NewGroup except the initial GroupContext includes the provided extensions.
//
// Deprecated: use NewGroup(..., WithExtensions(extensions)).
func NewGroupWithExtensions(
	groupID *GroupID,
	cipherSuite ciphersuite.CipherSuite,
	keyPackage *keypackages.KeyPackage,
	privKeys *keypackages.KeyPackagePrivateKeys,
	extensions []Extension,
) (*Group, error) {
	return NewGroup(groupID, cipherSuite, keyPackage, privKeys, WithExtensions(extensions))
}

// AddMember creates a proposal to add a new member to the group.
//
// RFC 9420 §12.1.1
// The proposal is added to the group's pending proposal list and must be
// committed (via Commit) to take effect.
//
// Returns the generated Proposal which can be sent to other members.
func (g *Group) AddMember(keyPackage *keypackages.KeyPackage) (*Proposal, error) {
	if g.state != StateOperational {
		return nil, ErrGroupNotOperational
	}
	if keyPackage == nil {
		return nil, ErrNilKeyPackage
	}
	if err := keyPackage.Validate(); err != nil {
		return nil, fmt.Errorf("invalid key package: %w", err)
	}
	if err := g.validateAddKeyPackageUniqueness(keyPackage); err != nil {
		return nil, err
	}

	// Create Add proposal
	proposal := &Proposal{
		Type: ProposalTypeAdd,
		Add: &AddProposal{
			KeyPackage: keyPackage,
		},
	}

	// Store proposal
	g.proposals.AddProposal(proposal, g.ownLeafIndex)

	return proposal, nil
}

func (g *Group) validateAddKeyPackageUniqueness(keyPackage *keypackages.KeyPackage) error {
	if keyPackage == nil {
		return ErrNilKeyPackage
	}
	if len(keyPackage.InitKey) == 0 {
		return nil
	}
	initKey := string(keyPackage.InitKey)
	for _, member := range g.members {
		if member == nil || !member.Active || member.KeyPackage == nil {
			continue
		}
		if string(member.KeyPackage.InitKey) == initKey {
			return fmt.Errorf("init key in Add proposal already in use by group member: %w", ErrInvalidProposal)
		}
	}
	if g.proposals != nil {
		for _, stored := range g.proposals.Proposals {
			if stored.Proposal == nil || stored.Proposal.Type != ProposalTypeAdd || stored.Proposal.Add == nil || stored.Proposal.Add.KeyPackage == nil {
				continue
			}
			if string(stored.Proposal.Add.KeyPackage.InitKey) == initKey {
				return fmt.Errorf("duplicate init key in Add proposals: %w", ErrInvalidProposal)
			}
		}
	}
	return nil
}

// UpdateMember updates the own leaf node.
//
// This creates an Update proposal with a new LeafNode.
func (g *Group) UpdateMember(
	newLeafNode *treesync.LeafNodeData,
	privateKeys *keypackages.KeyPackagePrivateKeys,
) (*Proposal, error) {
	if g.state != StateOperational {
		return nil, ErrGroupNotOperational
	}
	if newLeafNode == nil {
		return nil, ErrNilLeafNode
	}
	if privateKeys == nil {
		return nil, fmt.Errorf("private keys are nil")
	}
	if privateKeys.SignatureKey == nil && len(privateKeys.Ed25519SignatureKey) == 0 {
		return nil, fmt.Errorf("no signature key available")
	}

	// source = 2 (update); TBS includes group_id + leaf_index per RFC §7.2.
	newLeafNode.LeafNodeSource = 2
	sigKey := privateKeys.GetSignaturePrivateKey()
	tbs := newLeafNode.MarshalTBSWithContext(g.groupContext.GroupID.AsSlice(), uint32(g.ownLeafIndex))
	sig, err := ciphersuite.SignWithLabel(sigKey, "LeafNodeTBS", tbs)
	if err != nil {
		return nil, fmt.Errorf("signing leaf node: %w", err)
	}
	newLeafNode.Signature = sig.AsSlice()

	// Convert treesync leaf data to keypackages leaf node.
	kpLeafNode := &keypackages.LeafNode{
		EncryptionKey:     newLeafNode.EncryptionKey,
		SignatureKey:      newLeafNode.SignatureKey,
		SignatureKeyBytes: append([]byte(nil), newLeafNode.SignatureKeyRaw...),
		Credential:        newLeafNode.Credential,
		Capabilities:      treeSyncToKeyPackageCapabilities(newLeafNode.Capabilities),
		Lifetime:          treeSyncToKeyPackageLifetime(newLeafNode.Lifetime),
	}

	// Create Update proposal
	proposal := &Proposal{
		Type: ProposalTypeUpdate,
		Update: &UpdateProposal{
			LeafNode: kpLeafNode,
		},
	}

	// Store proposal
	g.proposals.AddProposal(proposal, g.ownLeafIndex)
	return proposal, nil
}

// SelfUpdate creates an Update proposal with a fresh encryption key, signed
// with the caller-supplied signature key. This is the entry point for the
// interop gRPC UpdateProposal RPC, which only provides a state_id — all
// key material is derived from the current group state.
func (g *Group) SelfUpdate(sigKey *ciphersuite.SignaturePrivateKey) (*Proposal, error) {
	if g.state != StateOperational {
		return nil, ErrGroupNotOperational
	}
	if sigKey == nil {
		return nil, ErrNilSignaturePrivateKey
	}

	// Get current own leaf to copy credential/capabilities/lifetime.
	currentLeaf := g.ratchetTree.GetLeaf(treesync.LeafIndex(g.ownLeafIndex))
	if currentLeaf == nil || currentLeaf.LeafData == nil {
		return nil, ErrOwnLeafNotFound
	}
	ld := currentLeaf.LeafData

	// Generate a fresh HPKE key pair for the new leaf.
	newEncPriv, err := g.cipherSuite.Curve().GenerateKey(rand.Reader)
	if err != nil {
		return nil, fmt.Errorf("generating new leaf encryption key: %w", err)
	}
	newEncPub := newEncPriv.PublicKey().Bytes()
	// Store the private key; it will be needed to decrypt the UpdatePath when
	// this proposal is committed in a received commit (RFC §12.4.3.3).
	secureZeroBytes(g.pendingUpdatePrivKey)
	g.pendingUpdatePrivKey = newEncPriv.Bytes()

	// Build the new leaf node (LeafNodeSource=2 for update per RFC §7.2).
	// Use SigKeyBytes() to ensure SignatureKeyRaw is always set: for ECDSA leaves
	// (CS2) after a commit, SignatureKey holds the *ecdsa.PublicKey and SignatureKeyRaw
	// is nil, so a direct copy of SignatureKeyRaw would produce an empty TBS field.
	newLN := &treesync.LeafNodeData{
		EncryptionKey:   newEncPub,
		SignatureKeyRaw: append([]byte(nil), ld.SigKeyBytes()...),
		Credential:      ld.Credential,
		Capabilities:    ld.Capabilities,
		Lifetime:        ld.Lifetime,
		LeafNodeSource:  2,
	}

	tbs := newLN.MarshalTBSWithContext(g.groupContext.GroupID.AsSlice(), uint32(g.ownLeafIndex))
	sig, err := ciphersuite.SignWithLabel(sigKey, "LeafNodeTBS", tbs)
	if err != nil {
		return nil, fmt.Errorf("signing leaf node: %w", err)
	}
	newLN.Signature = sig.AsSlice()

	kpLeafNode := &keypackages.LeafNode{
		EncryptionKey:     newEncPub,
		SignatureKeyBytes: append([]byte(nil), ld.SigKeyBytes()...),
		Credential:        ld.Credential,
		Capabilities:      treeSyncToKeyPackageCapabilities(ld.Capabilities),
		Lifetime:          treeSyncToKeyPackageLifetime(ld.Lifetime),
		Signature:         newLN.Signature,
		LeafNodeSource:    2, // update per RFC §7.2
	}

	proposal := &Proposal{
		Type:   ProposalTypeUpdate,
		Update: &UpdateProposal{LeafNode: kpLeafNode},
	}
	g.proposals.AddProposal(proposal, g.ownLeafIndex)
	return proposal, nil
}

// RemoveMember creates a proposal to remove a member from the group.
//
// RFC 9420 §12.1.3
// The proposal is added to the pending proposal list. The removed member
// will not be able to read messages sent after this proposal is committed.
func (g *Group) RemoveMember(leafIndex LeafNodeIndex) (*Proposal, error) {
	if g.state != StateOperational {
		return nil, ErrGroupNotOperational
	}

	// Validate leaf index
	if int(leafIndex) >= int(g.ratchetTree.NumLeaves) {
		return nil, fmt.Errorf("invalid leaf index: %d", leafIndex)
	}

	// Create Remove proposal
	proposal := &Proposal{
		Type: ProposalTypeRemove,
		Remove: &RemoveProposal{
			Removed: leafIndex,
		},
	}

	// Store proposal
	g.proposals.AddProposal(proposal, g.ownLeafIndex)

	return proposal, nil
}

// Commit applies all pending proposals and creates a new epoch.
//
// RFC 9420 §12.4
// This is the main function to advance the group to a new epoch.
// It generates a Commit message (as a PublicMessage by default) that should be
// broadcast to the group. A Welcome message should also be generated for new members.
func (g *Group) Commit(
	sigPrivKey *ciphersuite.SignaturePrivateKey,
	sigPubKey *ciphersuite.SignaturePublicKey,
	externalPsks []schedule.Psk,
) (*StagedCommit, error) {
	return g.CommitWithContext(context.Background(), sigPrivKey, sigPubKey, externalPsks, framing.WireFormatPublicMessage)
}

// CommitWithFormat creates a Commit using a specific wire format.
func (g *Group) CommitWithFormat(
	sigPrivKey *ciphersuite.SignaturePrivateKey,
	sigPubKey *ciphersuite.SignaturePublicKey,
	externalPsks []schedule.Psk,
	format framing.WireFormat,
) (*StagedCommit, error) {
	return g.CommitWithContext(context.Background(), sigPrivKey, sigPubKey, externalPsks, format)
}

// CommitWithContext creates a Commit with support for context cancellation.
func (g *Group) CommitWithContext(
	ctx context.Context,
	sigPrivKey *ciphersuite.SignaturePrivateKey,
	sigPubKey *ciphersuite.SignaturePublicKey,
	externalPsks []schedule.Psk,
	format framing.WireFormat,
) (*StagedCommit, error) {
	select {
	case <-ctx.Done():
		return nil, ctx.Err()
	default:
	}

	if g.state != StateOperational {
		return nil, ErrGroupNotOperational
	}

	// Empty commits (no proposals) are valid per RFC 9420 §12.4.

	// Filter and validate proposals (RFC §12.2)
	filtered, err := g.FilterProposalsForCommit(nil)
	if err != nil {
		return nil, fmt.Errorf("filtering proposals: %w", err)
	}

	proposals := make([]*Proposal, len(filtered))
	proposalSenders := make([]LeafNodeIndex, len(filtered))
	for i, fp := range filtered {
		proposals[i] = fp.Proposal
		proposalSenders[i] = fp.Sender
	}

	// Clone tree, apply proposals provisionally.
	// Track newly added leaves (Add proposals) to exclude them from
	// UpdatePath encryption (RFC §12.4.1: new members get commit_secret via Welcome).
	// Also collect new extensions from any GroupContextExtensions proposal for newGC.
	treeDiff := g.ratchetTree.Clone()
	excluded := make(map[treesync.LeafIndex]bool)
	newExtensions := g.groupContext.Extensions // default: carry forward current extensions
	for _, fp := range filtered {
		switch {
		case fp.Proposal.Type == ProposalTypeAdd && fp.Proposal.Add != nil && fp.Proposal.Add.KeyPackage != nil && fp.Proposal.Add.KeyPackage.LeafNode != nil:
			leafData := *keyPackageLeafToTreeSync(fp.Proposal.Add.KeyPackage.LeafNode)
			addedIdx, _ := treeDiff.AddLeaf(leafData)
			excluded[addedIdx] = true
		case fp.Proposal.Type == ProposalTypeRemove && fp.Proposal.Remove != nil:
			// Truncation is deferred until after ALL proposals are applied
			// (matching OpenMLS behavior), so that AddLeaf slot selection
			// and UnmergedLeaves are consistent across implementations.
			removedLeaf := treesync.LeafIndex(fp.Proposal.Remove.Removed)
			for _, nodeIdx := range treeDiff.DirectPath(removedLeaf) {
				treeDiff.BlankNode(nodeIdx)
			}
		default:
			if err := g.applyProposalToTree(fp.Proposal, treeDiff, fp.Sender); err != nil {
				return nil, fmt.Errorf("applying proposal to tree: %w", err)
			}
		}
		// Collect new extensions from GCE proposals for the new epoch GroupContext.
		// Normalize nil extensions to empty slice so the nil-check in createUpdatePath
		// correctly distinguishes "GCE present (even if empty)" from "no GCE (inherit)".
		if fp.Proposal.Type == ProposalTypeGroupContextExtensions && fp.Proposal.GroupContextExtensions != nil {
			exts := fp.Proposal.GroupContextExtensions.Extensions
			if exts == nil {
				exts = []Extension{}
			}
			newExtensions = exts
		}
	}
	// RFC §12.1.3 step 4: truncate trailing blank leaves ONCE after all
	// proposals are applied (not per-Remove). This matches OpenMLS behavior
	// and ensures AddLeaf slot selection and UnmergedLeaves are consistent.
	treeDiff.TruncateTrailingBlanks()
	treeDiff = treeDiff.ExpandToPowerOf2()

	// Generate UpdatePath if necessary (RFC §12.4.1).
	// If the committer is the only member of the group, omit the path;
	// new members receive the commit_secret via the Welcome message instead.
	var updatePath *UpdatePath
	var commitSecret *ciphersuite.Secret
	var allPathSecrets []*ciphersuite.Secret
	var committerDP, committerCopath []treesync.NodeIndex
	var committerLevels []int

	if g.ratchetTree.LeafCount() > 1 {
		updatePath, commitSecret, allPathSecrets, committerDP, committerCopath, committerLevels, err = g.createUpdatePath(treeDiff, sigPrivKey, sigPubKey, excluded, newExtensions)
		if err != nil {
			return nil, fmt.Errorf("creating update path: %w", err)
		}
	} else {
		commitSecret = ciphersuite.ZeroSecretCS(g.cipherSuite)
	}

	// Build Commit structure — use by-reference for proposals received from the
	// network (they have a stored ref), inline for locally-generated proposals.
	// RFC 9420 §12.4: "The committer SHOULD include those proposals by reference."
	// mlspp treats all inline proposals as if sent by the committer, so using
	// by-reference for others' proposals avoids "Duplicate signature key" errors.
	commit := &Commit{
		Proposals: make([]ProposalOrRef, len(filtered)),
		Path:      updatePath,
	}

	for i, fp := range filtered {
		if len(fp.Ref) > 0 {
			commit.Proposals[i] = ProposalOrRef{ProposalRef: fp.Ref}
		} else {
			commit.Proposals[i] = ProposalOrRef{Proposal: fp.Proposal}
		}
	}

	// Create AuthenticatedContent and sign
	content := framing.FramedContent{
		GroupID: g.groupID.AsSlice(),
		Epoch:   g.epoch.AsUint64(),
		Sender:  framing.Sender{Type: framing.SenderTypeMember, LeafIndex: uint32(g.ownLeafIndex)},
		Body:    framing.CommitBody{Data: commit.Marshal()},
	}

	groupContextBytes := g.groupContext.Marshal()
	ac := &framing.AuthenticatedContent{
		WireFormat:   format,
		Content:      content,
		Auth:         framing.FramedContentAuthData{},
		GroupContext: groupContextBytes,
	}

	// Sign the TBS with label (RFC §6.1 / §5.1.2)
	sig, err := ciphersuite.SignWithLabel(sigPrivKey, "FramedContentTBS", ac.MarshalTBS())
	if err != nil {
		return nil, fmt.Errorf("signing commit: %w", err)
	}
	ac.Auth.Signature = sig

	// Compute confirmed_transcript_hash (RFC §8.2)
	cthi, err := framing.NewConfirmedTranscriptHashInput(ac)
	if err != nil {
		return nil, fmt.Errorf("creating transcript hash input: %w", err)
	}
	confirmedHash, err := cthi.Compute(g.cipherSuite, g.interimTranscriptHash)
	if err != nil {
		return nil, fmt.Errorf("computing confirmed transcript hash: %w", err)
	}

	// Build the provisional GroupContext for the next epoch.
	newTreeHash := treeDiff.TreeHash()
	newGC := &GroupContext{
		Version:                 g.groupContext.Version,
		CipherSuite:             g.cipherSuite,
		GroupID:                 g.groupContext.GroupID,
		Epoch:                   NewGroupEpoch(g.epoch.AsUint64() + 1),
		TreeHash:                newTreeHash,
		ConfirmedTranscriptHash: confirmedHash,
		Extensions:              newExtensions,
	}

	// Advance the key schedule to compute the next epoch confirmation_key.
	// Clone InitSecret so the staging computation does not consume it: if this
	// commit is later discarded (DS picks a competing commit), the original
	// InitSecret must remain intact to process the winning commit.
	newGCBytes := newGC.Marshal()
	newKS := schedule.NewKeySchedule(g.cipherSuite, g.epochSecrets.InitSecret.Clone())
	newKS.SetCommitSecret(commitSecret)
	joinerSecretVal, err := newKS.ComputeJoinerSecret(newGCBytes)
	if err != nil {
		return nil, fmt.Errorf("new epoch joiner secret: %w", err)
	}
	// Clone joiner_secret BEFORE ComputePskSecret zeroes it via HKDFExtract.
	// The clone is stored in StagedCommit.JoinerSecret for use by CreateWelcome.
	joinerSecretForWelcome := joinerSecretVal.Clone()
	// Collect PSKs from proposals (RFC §8.4); merge with any externally supplied PSKs.
	proposalPsks, err := g.collectPSKsFromProposals(proposals)
	if err != nil {
		return nil, fmt.Errorf("collecting PSKs from proposals: %w", err)
	}
	allPsks := append([]schedule.Psk(nil), proposalPsks...)
	allPsks = append(allPsks, externalPsks...)
	if _, err = newKS.ComputePskSecret(allPsks); err != nil {
		return nil, fmt.Errorf("new epoch psk secret: %w", err)
	}
	if _, err = newKS.ComputeEpochSecret(newGCBytes); err != nil {
		return nil, fmt.Errorf("new epoch epoch secret: %w", err)
	}
	newEpochSecrets, err := newKS.DeriveEpochSecrets()
	if err != nil {
		return nil, fmt.Errorf("deriving new epoch secrets: %w", err)
	}

	// confirmation_tag = MAC(confirmation_key, confirmed_transcript_hash) (RFC §8.2)
	confirmationTag := schedule.ComputeConfirmationTag(
		g.cipherSuite,
		newEpochSecrets.ConfirmationKey.AsSlice(),
		confirmedHash,
	)
	ac.Auth.ConfirmationTag = confirmationTag

	newInterimHash := schedule.ComputeInterimTranscriptHash(g.cipherSuite, confirmedHash, confirmationTag)

	// Compute membership_tag for PublicMessage commits (RFC §6.2).
	// Uses the CURRENT epoch's membership_key (before MergeCommit advances the group).
	var membershipTag []byte
	if format == framing.WireFormatPublicMessage &&
		content.Sender.Type == framing.SenderTypeMember &&
		g.epochSecrets != nil && g.epochSecrets.MembershipKey != nil {
		tbm := ac.MarshalTBM()
		membershipTag = schedule.ComputeMembershipTag(g.cipherSuite, g.epochSecrets.MembershipKey.AsSlice(), tbm)
	}

	// Extract PskIDs from PSK proposals for CreateWelcome
	var pskIDs []PskID
	for _, proposal := range proposals {
		if proposal.Type == ProposalTypePreSharedKey && proposal.PreSharedKey != nil {
			pskIDs = append(pskIDs, proposal.PreSharedKey.PskID)
		}
	}

	// Create StagedCommit with precomputed values for committer
	stagedCommit := &StagedCommit{
		commit:                  commit,
		proposals:               proposals,
		proposalSenders:         proposalSenders,
		authenticatedContent:    ac,
		rootPathSecret:          commitSecret,
		joinerSecret:            joinerSecretForWelcome,
		precomputedEpochSecrets: newEpochSecrets,
		precomputedGroupContext: newGC,
		precomputedInterimHash:  newInterimHash,
		pskIDs:                  pskIDs,
		rawPskSecret:            newKS.GetRawPskSecret(),
		pathSecrets:             allPathSecrets,
		committerFilteredLevels: committerLevels,
		committerDirectPath:     committerDP,
		committerCopath:         committerCopath,
		treeAfterProposals:      treeDiff,
		membershipTag:           membershipTag,
	}

	g.pendingCommit = stagedCommit
	g.state = StatePendingCommit

	return stagedCommit, nil
}

// filteredDirectPathLevels returns the direct path, copath, and the subset of
// copath indices where the resolution is non-empty (RFC §12.4.1: UpdatePath.Nodes
// only covers parents whose sibling's resolution is non-empty).
// filteredDirectPathLevels returns the direct path, copath, and the subset of
// copath indices where the FULL resolution is non-empty (RFC §12.4.1).
// Note: newly-added-leaf exclusions only affect HPKECiphertext targets, NOT
// which levels appear in the filtered path.
func filteredDirectPathLevels(tree *treesync.RatchetTree, senderLeafIdx treesync.LeafIndex) (directPath, copath []treesync.NodeIndex, levels []int) {
	directPath = tree.DirectPath(senderLeafIdx)
	copath = tree.Copath(senderLeafIdx)
	levels = make([]int, 0, len(copath))
	for i, copathNode := range copath {
		if len(tree.Resolution(copathNode)) > 0 {
			levels = append(levels, i)
		}
	}
	return directPath, copath, levels
}

// createUpdatePath generates an UpdatePath (RFC §12.4.1).
// Uses filtered direct path: only levels where the copath sibling has non-empty
// resolution get a new encryption key and an UpdatePathNode entry.
// Path secrets: pathSecrets[0] = leaf_secret; pathSecrets[k] = DeriveSecret^k(leaf_secret, "path").
// Filtered level m encrypts pathSecrets[N-F+m+1] so receivers derive the node key as
// DeriveKeyPair(DeriveSecret(decrypted, "node")) and chain F-m times to commitSecret = pathSecrets[N+1].
//
//nolint:gocritic // Needs multiple returns to avoid allocating an intermediate struct in a hot path
func (g *Group) createUpdatePath(
	tree *treesync.RatchetTree,
	sigPrivKey *ciphersuite.SignaturePrivateKey,
	sigPubKey *ciphersuite.SignaturePublicKey,
	excluded map[treesync.LeafIndex]bool, // newly added leaves excluded from UpdatePath encryption (RFC §12.4.1)
	newExtensions []Extension, // GCE-updated extensions for provisional GroupContext (nil = current)
) (*UpdatePath, *ciphersuite.Secret, []*ciphersuite.Secret, []treesync.NodeIndex, []treesync.NodeIndex, []int, error) {
	leafSecret, err := ciphersuite.NewSecretRandomCS(g.cipherSuite)
	if err != nil {
		return nil, nil, nil, nil, nil, nil, err
	}

	senderLeafIdx := treesync.LeafIndex(g.ownLeafIndex)
	directPath := tree.DirectPath(senderLeafIdx)
	N := len(directPath) - 1

	// Derive path secrets for all N non-leaf levels, plus one extra so that
	// pathSecrets[k] is the path_secret for parent k in the RFC sense:
	//   pathSecrets[0]   = leaf_secret (random seed, used only for leaf HPKE key)
	//   pathSecrets[1]   = DeriveSecret(pathSecrets[0], "path") → path_secret[0] for first parent
	//   pathSecrets[k]   = path_secret for k-th parent
	//   pathSecrets[N+1] = commit_secret = DeriveSecret^(N+1)(leaf_secret)
	// Encrypting pathSecrets[N-F+m+1] at filtered level m ensures the receiver can
	// derive the node key as DeriveKeyPair(DeriveSecret(pathSecrets[N-F+m+1], "node"))
	// (matching the published key), then chain forward to pathSecrets[N+1] = commit_secret.
	pathSecrets := make([]*ciphersuite.Secret, N+2)
	pathSecrets[0] = leafSecret
	for i := 1; i <= N+1; i++ {
		pathSecrets[i], err = pathSecrets[i-1].DeriveSecret(g.cipherSuite, "path")
		if err != nil {
			return nil, nil, nil, nil, nil, nil, err
		}
	}

	// Compute filtered levels excluding newly added leaves (RFC §12.4.1).
	// New members receive the commit_secret via Welcome, not via UpdatePath.
	_, copath, levels := filteredDirectPathLevels(tree, senderLeafIdx)
	F := len(levels)

	// RFC 9420 §7.5 / §12.4.2: blank all intermediate nodes on the committer's
	// direct path before publishing new keys at filtered levels.
	for i := 1; i < len(directPath); i++ {
		tree.BlankNode(directPath[i])
	}

	// Apply encryption keys to filtered parent nodes (RFC §12.4.1).
	// Also store private keys so this member can later decrypt commits where one
	// of these ancestor nodes appears in the copath resolution (RFC §12.4.2).
	pubKeys := make([][]byte, F)
	for m, level := range levels {
		// pathSecrets[N-F+m+1] is the path_secret for this parent node.
		// Receivers decrypt this value and derive: node_key = DeriveKeyPair(DeriveSecret(ps, "node")).
		// Using pathSecrets[N-F+m+1] ensures the node key differs from the leaf key
		// (which uses DeriveSecret(pathSecrets[0], "node") = DeriveSecret(leaf_secret, "node")).
		nodePs := pathSecrets[N-F+m+1]
		nodeSecret, _ := nodePs.DeriveSecret(g.cipherSuite, "node")
		privKey, _ := ciphersuite.DeriveKeyPair(g.cipherSuite, nodeSecret.AsSlice())
		secureZeroSecret(nodeSecret)
		pubKeys[m] = privKey.PublicKey().Bytes()

		nodeIdx := directPath[level+1]
		tree.Nodes[nodeIdx].EncryptionKey, _ = g.cipherSuite.Curve().NewPublicKey(pubKeys[m])
		tree.Nodes[nodeIdx].State = treesync.NodeStatePresent
		tree.Nodes[nodeIdx].UnmergedLeaves = nil

		// Store private key: needed if a future copath resolution includes this node.
		g.setPathNodePrivKey(nodeIdx, privKey.Bytes())
	}

	// Compute parent hashes top-down (RFC §7.9).
	// Blank/empty parents pass through their parent_hash; present parents compute it.
	rootIdx := tree.Root()
	tree.Nodes[rootIdx].ParentHash = []byte{}
	for i := len(directPath) - 2; i >= 0; i-- {
		nodeIdx := directPath[i]
		parentIdx, _ := tree.Parent(nodeIdx)
		parent := &tree.Nodes[parentIdx]
		var ph []byte
		if parent.State == treesync.NodeStatePresent {
			var parentKey []byte
			if parent.EncryptionKey != nil {
				parentKey = parent.EncryptionKey.Bytes()
			}
			siblingIdx := tree.GetSibling(nodeIdx)
			siblingHash := tree.HashNode(siblingIdx)
			ph = treesync.ComputeParentHash(parentKey, parent.ParentHash, siblingHash, g.cipherSuite.HashFunction())
		} else {
			ph = parent.ParentHash
		}
		tree.Nodes[nodeIdx].ParentHash = ph
	}

	var caps *treesync.LeafNodeCapabilities
	if ownLeaf := g.ratchetTree.GetLeaf(senderLeafIdx); ownLeaf != nil && ownLeaf.LeafData != nil {
		caps = ownLeaf.LeafData.Capabilities
	}
	if caps == nil {
		caps = &treesync.LeafNodeCapabilities{}
	}

	// Determine signature key bytes to embed in the leaf node.
	// For ECDSA: convert to *ecdsa.PublicKey (and keep raw bytes nil).
	// For Ed25519: store raw bytes only (SignatureKey stays nil).
	var sigPubKeyECDSA *ecdsa.PublicKey
	var sigPubKeyRaw []byte
	rawSigPub := sigPubKey.AsSlice()
	if len(rawSigPub) == 65 && rawSigPub[0] == 0x04 {
		// ECDSA uncompressed point
		converted, err := sigPubKey.ToECDSA()
		if err != nil {
			return nil, nil, nil, nil, nil, nil, fmt.Errorf("converting signature public key: %w", err)
		}
		sigPubKeyECDSA = converted
	} else {
		// Ed25519 or other: store raw bytes
		sigPubKeyRaw = append([]byte(nil), rawSigPub...)
	}

	// Derive leaf HPKE key pair from node_secret = DeriveSecret(leafSecret, "node") (RFC §12.4.2).
	leafNodeSecret, err := leafSecret.DeriveSecret(g.cipherSuite, "node")
	if err != nil {
		return nil, nil, nil, nil, nil, nil, fmt.Errorf("deriving leaf node secret: %w", err)
	}
	leafPrivKey, err := ciphersuite.DeriveKeyPair(g.cipherSuite, leafNodeSecret.AsSlice())
	secureZeroSecret(leafNodeSecret)
	if err != nil {
		return nil, nil, nil, nil, nil, nil, fmt.Errorf("deriving leaf key pair: %w", err)
	}
	leafNodeData := &treesync.LeafNodeData{
		EncryptionKey:   leafPrivKey.PublicKey().Bytes(),
		SignatureKey:    sigPubKeyECDSA,
		SignatureKeyRaw: sigPubKeyRaw,
		Credential:      g.members[g.ownLeafIndex].Credential,
		Capabilities:    caps,
		Lifetime:        nil, // source=commit: Lifetime not included in TBS (RFC §7.2)
		LeafNodeSource:  3,
		ParentHash:      tree.Nodes[directPath[0]].ParentHash,
	}
	// source=commit; TBS includes group_id + leaf_index per RFC §7.2.
	tbs := leafNodeData.MarshalTBSWithContext(g.groupContext.GroupID.AsSlice(), uint32(senderLeafIdx))
	sig, err := ciphersuite.SignWithLabel(sigPrivKey, "LeafNodeTBS", tbs)
	if err != nil {
		return nil, nil, nil, nil, nil, nil, fmt.Errorf("signing leaf node TBS: %w", err)
	}
	leafNodeData.Signature = sig.AsSlice()

	// Apply leaf to tree for provisional tree hash computation.
	if err := tree.SetLeaf(senderLeafIdx, *leafNodeData); err != nil {
		return nil, nil, nil, nil, nil, nil, fmt.Errorf("setting leaf in tree: %w", err)
	}

	// Compute provisional GroupContext (RFC §12.4.1: next epoch + tree_hash_after).
	// Use GCE-updated extensions if provided, otherwise inherit current extensions.
	provExts := g.groupContext.Extensions
	if newExtensions != nil {
		provExts = newExtensions
	}
	provGCBytes := (&GroupContext{
		Version:                 g.groupContext.Version,
		CipherSuite:             g.groupContext.CipherSuite,
		GroupID:                 g.groupContext.GroupID,
		Epoch:                   NewGroupEpoch(g.groupContext.Epoch.AsUint64() + 1),
		TreeHash:                tree.TreeHash(),
		ConfirmedTranscriptHash: g.groupContext.ConfirmedTranscriptHash,
		Extensions:              provExts,
	}).Marshal()

	// Encrypt path secrets for each filtered level using provisional GC as context.
	// Encrypt pathSecrets[N-F+m+1] so receivers can derive the node key directly
	// as DeriveKeyPair(DeriveSecret(decrypted, "node")) and chain to commit_secret.
	nodes := make([]UpdatePathNode, F)
	type encResult struct {
		idx  int
		node UpdatePathNode
		err  error
	}
	results := make([]encResult, F)
	var wg sync.WaitGroup
	for m, level := range levels {
		wg.Add(1)
		go func(m, level int) {
			defer wg.Done()
			ps := pathSecrets[N-F+m+1]
			res := tree.ResolutionWithExclusions(copath[level], excluded)
			encryptedSecrets := make([]ciphersuite.HpkeCiphertext, len(res))
			for j, resIdx := range res {
				resNode := &tree.Nodes[resIdx]
				var encKeyBytes []byte
				if treesync.IsLeaf(resIdx) {
					if resNode.LeafData != nil {
						encKeyBytes = resNode.LeafData.EncryptionKey
					}
				} else if resNode.EncryptionKey != nil {
					encKeyBytes = resNode.EncryptionKey.Bytes()
				}
				if len(encKeyBytes) == 0 {
					continue
				}
				ct, err := ciphersuite.EncryptWithLabel(encKeyBytes, "UpdatePathNode", provGCBytes, ps.AsSlice(), g.cipherSuite)
				if err != nil {
					results[m] = encResult{idx: m, err: err}
					return
				}
				encryptedSecrets[j] = *ct
			}
			results[m] = encResult{
				idx: m,
				node: UpdatePathNode{
					EncryptionKey:        pubKeys[m],
					EncryptedPathSecrets: encryptedSecrets,
				},
			}
		}(m, level)
	}
	wg.Wait()
	for _, result := range results {
		if result.err != nil {
			return nil, nil, nil, nil, nil, nil, result.err
		}
		nodes[result.idx] = result.node
	}

	// Stage the new leaf private key. myLeafEncryptionKey is updated only in
	// MergeCommit so that DiscardPendingCommit can roll back without restoring it.
	g.pendingLeafKey = leafPrivKey.Bytes()

	commitSecret := pathSecrets[N+1]
	return &UpdatePath{LeafNode: leafNodeData, Nodes: nodes}, commitSecret, pathSecrets, directPath, copath, levels, nil
}

// provisionalGroupContextBytes computes the GroupContext bytes with the provisional tree hash.
// RFC 9420 §12.4.1: UpdatePathNode HPKE context = serialized GroupContext where
// tree_hash = hash(tree after applying proposals + full UpdatePath).
// If treeAlreadyDiff != nil, uses that tree as the base (for external commits).
// buildProvisionalTree applies the UpdatePath changes to a tree:
// 1. Set committer's leaf from UpdatePath.LeafNode
// 2. Blank committer's direct path intermediates
// 3. Apply UpdatePath encryption keys at filtered levels
// 4. Recompute parent_hash fields
// The returned tree is a clone — the input tree is not modified.
func buildProvisionalTree(tree *treesync.RatchetTree, senderLeafIdx treesync.LeafIndex, path *UpdatePath, cs ciphersuite.CipherSuite) *treesync.RatchetTree {
	provTree := tree.Clone()

	if path.LeafNode != nil {
		_ = provTree.SetLeaf(senderLeafIdx, *path.LeafNode)
	}

	// RFC §12.4.2 step 6: Blank ALL intermediate nodes on the committer's direct path.
	provDP := provTree.DirectPath(senderLeafIdx)
	for i := 1; i < len(provDP); i++ {
		provTree.BlankNode(provDP[i])
	}

	// Apply UpdatePath parent nodes using filtered direct path (RFC §12.4.1).
	provDP, _, provLevels := filteredDirectPathLevels(provTree, senderLeafIdx)
	for m, level := range provLevels {
		if m >= len(path.Nodes) {
			break
		}
		dpNodeIdx := provDP[level+1]
		encKeyBytes := path.Nodes[m].EncryptionKey
		if len(encKeyBytes) > 0 {
			if pubKey, err := cs.Curve().NewPublicKey(encKeyBytes); err == nil {
				provTree.Nodes[dpNodeIdx].EncryptionKey = pubKey
				provTree.Nodes[dpNodeIdx].State = treesync.NodeStatePresent
				provTree.Nodes[dpNodeIdx].UnmergedLeaves = nil
			}
		}
	}

	// Recompute parent_hash fields top-down for correct tree hash (RFC §7.9).
	if len(provDP) > 1 {
		rootIdx := provTree.Root()
		provTree.Nodes[rootIdx].ParentHash = []byte{}
		for k := len(provDP) - 2; k >= 0; k-- {
			childIdx := provDP[k]
			parentIdx := provDP[k+1]
			parent := &provTree.Nodes[parentIdx]
			var parentHash []byte
			if parent.State == treesync.NodeStatePresent {
				var parentKey []byte
				if parent.EncryptionKey != nil {
					parentKey = parent.EncryptionKey.Bytes()
				}
				siblingIdx := provTree.GetSibling(childIdx)
				siblingHash := provTree.HashNode(siblingIdx)
				parentHash = treesync.ComputeParentHash(parentKey, parent.ParentHash, siblingHash, cs.HashFunction())
			} else {
				parentHash = parent.ParentHash
			}
			if !treesync.IsLeaf(childIdx) {
				provTree.Nodes[childIdx].ParentHash = parentHash
			}
		}
	}

	provTree = provTree.ExpandToPowerOf2()

	return provTree
}

// provisionalGroupContextBytesFromTree computes the provisional GroupContext
// from an already-built provisional tree.
// newExtensions should reflect any GCE proposals applied in this commit;
// pass nil to inherit the current epoch's extensions unchanged.
func (g *Group) provisionalGroupContextBytesFromTree(provTree *treesync.RatchetTree, newExtensions []Extension) []byte {
	exts := g.groupContext.Extensions
	if newExtensions != nil {
		exts = newExtensions
	}
	provGC := &GroupContext{
		Version:                 g.groupContext.Version,
		CipherSuite:             g.groupContext.CipherSuite,
		GroupID:                 g.groupContext.GroupID,
		Epoch:                   NewGroupEpoch(g.groupContext.Epoch.AsUint64() + 1),
		TreeHash:                provTree.TreeHash(),
		ConfirmedTranscriptHash: g.groupContext.ConfirmedTranscriptHash,
		Extensions:              exts,
	}
	return provGC.Marshal()
}

// applyProposalToTree applies a proposal to a specific RatchetTree.
func (g *Group) applyProposalToTree(proposal *Proposal, tree *treesync.RatchetTree, senderIdx LeafNodeIndex) error {
	switch proposal.Type {
	case ProposalTypeAdd:
		leafData := *keyPackageLeafToTreeSync(proposal.Add.KeyPackage.LeafNode)
		tree.AddLeaf(leafData)
	case ProposalTypeRemove:
		removedLeaf := treesync.LeafIndex(proposal.Remove.Removed)
		for _, nodeIdx := range tree.DirectPath(removedLeaf) {
			tree.BlankNode(nodeIdx)
		}
		tree.TruncateTrailingBlanks()
	case ProposalTypeUpdate:
		leafIdx := treesync.LeafIndex(senderIdx)
		leafData := *keyPackageLeafToTreeSync(proposal.Update.LeafNode)
		if err := tree.SetLeaf(leafIdx, leafData); err != nil {
			return fmt.Errorf("setting leaf for update proposal: %w", err)
		}
		path := tree.DirectPath(leafIdx)
		for i := 1; i < len(path); i++ {
			tree.BlankNode(path[i])
		}
	case ProposalTypeGroupContextExtensions:
		// GCE does not change tree structure; no-op for provisional tree building.
		// The actual extensions update happens in MergeCommit via applyProposal.
	}
	return nil
}

// ProcessCommit processes a received commit.
// RFC 9420 §12.4.2
func (g *Group) ProcessCommit(stagedCommit *StagedCommit) error {
	if stagedCommit.authenticatedContent == nil {
		return ErrMissingAuthenticatedContent
	}
	return g.MergeCommit(stagedCommit)
}

// StoreProposal stores a proposal indexed by hash reference for future resolution (RFC 9420 §12.4).
// acBytes must be the serialized AuthenticatedContent of the proposal's PublicMessage.
//
// RFC 9420 §5.4: ProposalRef = RefHash("MLS 1.0 Proposal Reference", AuthenticatedContent).
// The input is the serialized AuthenticatedContent (wire_format + content + auth) without
// any MLSMessage version prefix.
func (g *Group) StoreProposal(p *Proposal, sender LeafNodeIndex, acBytes []byte) []byte {
	if g.proposalByRef == nil {
		g.proposalByRef = make(map[string]*Proposal)
	}
	ref := ComputeProposalRef(acBytes, g.cipherSuite)
	g.proposalByRef[string(ref)] = p
	g.proposals.AddProposalWithRef(p, sender, ref)
	return ref
}

// ProcessReceivedCommit processes a commit from another existing group member.
// Decrypts the path secret using the receiver's private HPKE key,
// then advances the group state. RFC 9420 §12.4.2
func (g *Group) ProcessReceivedCommit(
	ac *framing.AuthenticatedContent,
	senderLeafIdx treesync.LeafIndex,
	myHpkePrivKeyBytes []byte,
) error {
	// RFC §12.4.1: validate GroupID and epoch before any costly work.
	// GroupID is public protocol metadata, not secret material.
	if !bytes.Equal(ac.Content.GroupID, g.groupContext.GroupID.AsSlice()) {
		return &ErrGroupIDMismatch{
			Got:  append([]byte(nil), ac.Content.GroupID...),
			Want: append([]byte(nil), g.groupContext.GroupID.AsSlice()...),
		}
	}
	if ac.Content.Epoch != g.groupContext.Epoch.AsUint64() {
		return &ErrEpochMismatch{
			Got:  ac.Content.Epoch,
			Want: g.groupContext.Epoch.AsUint64(),
		}
	}

	commitBody, ok := ac.Content.Body.(framing.CommitBody)
	if !ok {
		return ErrNotACommit
	}

	commit, err := UnmarshalCommit(commitBody.Data)
	if err != nil {
		return fmt.Errorf("unmarshaling commit: %w", err)
	}

	switch ac.Content.Sender.Type {
	case framing.SenderTypeMember:
		// RFC §12.4.2: verify signature using the sender's leaf key from the tree.
		senderLeaf := g.ratchetTree.GetLeaf(senderLeafIdx)
		if senderLeaf == nil || senderLeaf.LeafData == nil {
			return fmt.Errorf("missing sender signature key")
		}
		rawKey := senderLeaf.LeafData.SigKeyBytes()
		if len(rawKey) == 0 {
			return fmt.Errorf("missing sender signature key")
		}
		pubKey := ciphersuite.NewMLSSignaturePublicKey(rawKey, g.cipherSuite.SignatureScheme())
		if err := ciphersuite.VerifyWithLabel(pubKey, "FramedContentTBS", ac.MarshalTBS(), ac.Auth.Signature); err != nil {
			return fmt.Errorf("commit signature verification failed: %w", err)
		}
	case framing.SenderTypeNewMemberCommit:
		// RFC §12.4.3.2: external committer's key is in the UpdatePath LeafNode.
		if commit.Path == nil || commit.Path.LeafNode == nil {
			return fmt.Errorf("external commit missing leaf node signature key")
		}
		rawKey := commit.Path.LeafNode.SigKeyBytes()
		if len(rawKey) == 0 {
			return fmt.Errorf("external commit missing leaf node signature key")
		}
		pubKey := ciphersuite.NewMLSSignaturePublicKey(rawKey, g.cipherSuite.SignatureScheme())
		if err := ciphersuite.VerifyWithLabel(pubKey, "FramedContentTBS", ac.MarshalTBS(), ac.Auth.Signature); err != nil {
			return fmt.Errorf("external commit signature verification failed: %w", err)
		}
	}

	isExternalCommit := ac.Content.Sender.Type == framing.SenderTypeNewMemberCommit

	// RFC §12.4.3.2: external commits MUST NOT include proposals by reference.
	if isExternalCommit {
		for _, por := range commit.Proposals {
			if len(por.ProposalRef) > 0 {
				return fmt.Errorf("external commit must not include proposals by reference: %w", ErrInvalidProposal)
			}
		}
	}

	// Resolver proposals: inline o por referencia hash.
	// Also collect per-proposal sender so we can apply them correctly to the tree.
	proposals := make([]*Proposal, 0, len(commit.Proposals))
	proposalSenders := make([]LeafNodeIndex, 0, len(commit.Proposals))
	for _, por := range commit.Proposals {
		if por.Proposal != nil {
			proposals = append(proposals, por.Proposal)
			// For inline Update proposals, infer the actual sender by matching
			// the proposal's signature key against the current tree. RFC §12.1.2:
			// a member updates their own leaf, so the sender is the leaf whose
			// current signature key matches the Update proposal's signature key.
			sender := LeafNodeIndex(senderLeafIdx) // default: committer
			if por.Proposal.Type == ProposalTypeUpdate && por.Proposal.Update != nil && por.Proposal.Update.LeafNode != nil {
				newSigKey := por.Proposal.Update.LeafNode.SignatureKeyBytes
				// Iterate Members map directly: after removals the tree is sparse,
				// so MemberCount() as an upper bound on leaf indices misses high slots.
				for leafIdx := range g.members {
					leaf := g.ratchetTree.GetLeaf(treesync.LeafIndex(leafIdx))
					// Update proposal sender inference compares public signature keys.
					if leaf != nil && leaf.LeafData != nil && bytes.Equal(leaf.LeafData.SigKeyBytes(), newSigKey) {
						sender = leafIdx
						break
					}
				}
			}
			proposalSenders = append(proposalSenders, sender)
		} else if len(por.ProposalRef) > 0 {
			if p, ok := g.proposalByRef[string(por.ProposalRef)]; ok {
				proposals = append(proposals, p)
				// Look up sender stored when the proposal was received.
				sender := LeafNodeIndex(senderLeafIdx) // fallback: committer
				for _, sp := range g.proposals.Proposals {
					if sp.Proposal == p {
						sender = sp.Sender
						break
					}
				}
				proposalSenders = append(proposalSenders, sender)
			} else {
				return ErrUnknownProposalRef
			}
		}
	}

	// RFC §12.4.3.2: an external commit MUST contain exactly one ExternalInit proposal.
	if isExternalCommit {
		extInitCount := 0
		for _, p := range proposals {
			if p.Type == ProposalTypeExternalInit {
				extInitCount++
			}
		}
		if extInitCount != 1 {
			return fmt.Errorf("external commit must contain exactly one ExternalInit proposal, got %d: %w",
				extInitCount, ErrInvalidProposal)
		}
	}

	// RFC §12.4.2: validate proposals. Build FilteredProposals for validation.
	// For member commits, all proposals are from internal senders (IsExternal=false).
	// External commit proposals are not filtered here — they are validated inline above.
	if !isExternalCommit {
		filteredForValidation := make([]FilteredProposal, len(proposals))
		for i, p := range proposals {
			filteredForValidation[i] = FilteredProposal{
				Proposal: p,
				Sender:   proposalSenders[i],
			}
		}
		pf := NewProposalFilter(g.groupContext, LeafNodeIndex(senderLeafIdx), g.members, g.cipherSuite, g.ratchetTree)
		if _, err := pf.FilterAndValidateProposals(filteredForValidation, nil); err != nil {
			return fmt.Errorf("commit contains invalid proposals: %w", err)
		}
	}

	// RFC §12.4.2: a commit MUST include a path if it covers a full commit
	// (no proposals), or contains at least one Update or Remove proposal.
	{
		hasUpdate, hasRemove := false, false
		for _, p := range proposals {
			switch p.Type {
			case ProposalTypeUpdate:
				hasUpdate = true
			case ProposalTypeRemove:
				hasRemove = true
			}
		}
		pathRequired := len(proposals) == 0 || hasUpdate || hasRemove
		if pathRequired && commit.Path == nil && !isExternalCommit {
			return fmt.Errorf("commit requires UpdatePath (no proposals or has Update/Remove) but path is absent: %w", ErrInvalidProposal)
		}
	}

	// RFC §12.4.2: Sort proposals by type before applying.
	// Order: GCE → Update → Remove → Add → PSK → ReInit → ExternalInit.
	sortProposalsByRFCOrder(proposals, proposalSenders)

	// Build tree with proposals applied, tracking newly added leaves (exclusion list).
	// Also collect new extensions from any GCE proposals for the provisional GroupContext.
	treeAfterProposals := g.ratchetTree.Clone()
	excluded := make(map[treesync.LeafIndex]bool)
	var newExtensions []Extension // nil = inherit current extensions
	for i, p := range proposals {
		switch {
		case p.Type == ProposalTypeAdd && p.Add != nil && p.Add.KeyPackage != nil && p.Add.KeyPackage.LeafNode != nil:
			leafData := *keyPackageLeafToTreeSync(p.Add.KeyPackage.LeafNode)
			addedIdx, _ := treeAfterProposals.AddLeaf(leafData)
			excluded[addedIdx] = true
		case p.Type == ProposalTypeRemove && p.Remove != nil:
			// Truncation is deferred until after ALL proposals are applied
			// (matching OpenMLS behavior), so that AddLeaf slot selection
			// and UnmergedLeaves are consistent across implementations.
			removedLeaf := treesync.LeafIndex(p.Remove.Removed)
			for _, nodeIdx := range treeAfterProposals.DirectPath(removedLeaf) {
				treeAfterProposals.BlankNode(nodeIdx)
			}
		default:
			if err := g.applyProposalToTree(p, treeAfterProposals, proposalSenders[i]); err != nil {
				return fmt.Errorf("applying proposal %d to provisional tree: %w", i, err)
			}
		}
		if p.Type == ProposalTypeGroupContextExtensions && p.GroupContextExtensions != nil {
			exts := p.GroupContextExtensions.Extensions
			if exts == nil {
				exts = []Extension{}
			}
			newExtensions = exts
		}
	}
	// RFC §12.1.3 step 4: truncate trailing blank leaves ONCE after all
	// proposals are applied (not per-Remove). This matches OpenMLS behavior
	// and ensures AddLeaf slot selection and UnmergedLeaves are consistent.
	treeAfterProposals.TruncateTrailingBlanks()

	// RFC §12.4.3.3: if the commit contains an Update proposal for our own leaf,
	// use PendingUpdatePrivKey (generated by SelfUpdate) instead of the current leaf key.
	// We detect our own UpdateProposal by matching the signature key (SelfUpdate keeps the
	// same sig key but generates a new enc key), regardless of how proposalSenders is set.
	decryptKey := myHpkePrivKeyBytes
	if g.pendingUpdatePrivKey != nil {
		ownLeaf := g.ratchetTree.GetLeaf(treesync.LeafIndex(g.ownLeafIndex))
		if ownLeaf != nil && ownLeaf.LeafData != nil {
			for _, p := range proposals {
				if p.Type == ProposalTypeUpdate && p.Update != nil && p.Update.LeafNode != nil {
					propKey := p.Update.LeafNode.SignatureKeyBytes
					ownKey := ownLeaf.LeafData.SigKeyBytes()
					// SelfUpdate detection compares public signature keys, not private key material.
					if bytes.Equal(propKey, ownKey) {
						decryptKey = g.pendingUpdatePrivKey
						break
					}
				}
			}
		}
	}

	// Decrypt path secret with our HPKE private key.
	var rootPathSecret *ciphersuite.Secret
	if ac.Content.Sender.Type == framing.SenderTypeNewMemberCommit {
		if commit.Path == nil || commit.Path.LeafNode == nil {
			return fmt.Errorf("external commit missing update path")
		}
		extLeafIdx, _ := treeAfterProposals.AddLeaf(*commit.Path.LeafNode)
		treeAfterProposals = treeAfterProposals.ExpandToPowerOf2()
		senderLeafIdx = extLeafIdx
		// The external joiner is excluded from copath resolution (same as newly added
		// members via Add proposals), because the sender excluded themselves when
		// computing filtered direct path levels during encryption.
		excluded[extLeafIdx] = true
		provTree := buildProvisionalTree(treeAfterProposals, senderLeafIdx, commit.Path, g.cipherSuite)
		provGCBytes := g.provisionalGroupContextBytesFromTree(provTree, newExtensions)
		rootPathSecret, err = g.decryptPathSecret(provTree, senderLeafIdx, commit.Path, decryptKey, provGCBytes, excluded)
		if err != nil {
			return fmt.Errorf("decrypting path secret (external): %w", err)
		}
	} else if commit.Path != nil {
		// RFC §12.4.2: the UpdatePath.LeafNode.EncryptionKey MUST differ from the
		// sender's current leaf key (forward secrecy — the old key must be retired).
		if senderLeaf := g.ratchetTree.GetLeaf(senderLeafIdx); senderLeaf != nil && senderLeaf.LeafData != nil {
			// UpdatePath leaf encryption keys are public HPKE public keys.
			if commit.Path.LeafNode != nil && bytes.Equal(commit.Path.LeafNode.EncryptionKey, senderLeaf.LeafData.EncryptionKey) {
				return fmt.Errorf("UpdatePath.LeafNode.EncryptionKey must differ from current leaf key: %w", ErrInvalidProposal)
			}
		}
		treeAfterProposals = treeAfterProposals.ExpandToPowerOf2()
		provTree := buildProvisionalTree(treeAfterProposals, senderLeafIdx, commit.Path, g.cipherSuite)
		provGCBytes := g.provisionalGroupContextBytesFromTree(provTree, newExtensions)
		rootPathSecret, err = g.decryptPathSecret(provTree, senderLeafIdx, commit.Path, decryptKey, provGCBytes, excluded)
		if err != nil {
			return fmt.Errorf("decrypting path secret: %w", err)
		}
	}

	staged := &StagedCommit{
		commit:               commit,
		proposals:            proposals,
		proposalSenders:      proposalSenders,
		authenticatedContent: ac,
		rootPathSecret:       rootPathSecret,
	}
	return g.MergeCommit(staged)
}

// decryptPathSecret decrypts the path secret from an UpdatePath for this receiver.
// Traverse the sender's filtered copath looking for the receiver's node in the resolution,
// decrypts with HPKE and derives forward to obtain the commit_secret.
// RFC 9420 §12.4.1: UpdatePath.Nodes has F entries (filtered levels only);
// nodes[m] encrypts pathSecrets[N-F+m+1], so derive F-m times to reach commitSecret = pathSecrets[N+1].
func (g *Group) decryptPathSecret(
	tree *treesync.RatchetTree,
	senderLeafIdx treesync.LeafIndex,
	updatePath *UpdatePath,
	myPrivKeyBytes []byte,
	gcBytes []byte, // provisional GroupContext bytes (RFC §12.4.1: context for HPKE)
	excluded map[treesync.LeafIndex]bool, // newly added leaves to exclude from resolution
) (*ciphersuite.Secret, error) {
	directPath, copath, levels := filteredDirectPathLevels(tree, senderLeafIdx)
	F := len(levels)
	myNodeIdx := treesync.LeafIndexToNodeIndex(treesync.LeafIndex(g.ownLeafIndex))

	// RFC §12.4.1: len(UpdatePath.Nodes) must equal the number of filtered direct path levels.
	if len(updatePath.Nodes) != F {
		return nil, fmt.Errorf("UpdatePath.Nodes length %d does not match filtered path length %d: %w",
			len(updatePath.Nodes), F, ErrInvalidProposal)
	}

	// RFC §12.4.1: for each filtered level m, len(EncryptedPathSecrets) must equal
	// the number of nodes in Resolution(copath[level]) \ excluded.
	for m, level := range levels {
		expectedCount := len(tree.ResolutionWithExclusions(copath[level], excluded))
		actualCount := len(updatePath.Nodes[m].EncryptedPathSecrets)
		if actualCount != expectedCount {
			return nil, fmt.Errorf("UpdatePath.Nodes[%d].EncryptedPathSecrets length %d, expected %d (resolution size): %w",
				m, actualCount, expectedCount, ErrInvalidProposal)
		}
	}

	// RFC §12.4.2: all EncryptionKeys in the UpdatePath MUST be unique (no duplicates
	// within the path itself and no collision with existing tree leaf keys).
	{
		pathKeys := make(map[string]bool, F+1)
		if updatePath.LeafNode != nil {
			pathKeys[string(updatePath.LeafNode.EncryptionKey)] = true
		}
		for m, node := range updatePath.Nodes {
			key := string(node.EncryptionKey)
			if pathKeys[key] {
				return nil, fmt.Errorf("UpdatePath.Nodes[%d].EncryptionKey duplicates another path key: %w",
					m, ErrInvalidProposal)
			}
			pathKeys[key] = true
		}
		// Check leaf keys in the tree for duplicates.
		for i := treesync.LeafIndex(0); i < treesync.LeafIndex(tree.NumLeaves); i++ {
			if leaf := tree.GetLeaf(i); leaf != nil && leaf.LeafData != nil && leaf.State == treesync.NodeStatePresent {
				if treesync.LeafIndexToNodeIndex(i) == treesync.LeafIndexToNodeIndex(senderLeafIdx) {
					continue // sender's own leaf is being replaced
				}
				if pathKeys[string(leaf.LeafData.EncryptionKey)] {
					return nil, fmt.Errorf("UpdatePath key duplicates existing tree leaf key: %w", ErrInvalidProposal)
				}
			}
		}
	}

	for m, level := range levels {
		res := tree.ResolutionWithExclusions(copath[level], excluded)
		for j, resIdx := range res {
			// Determine which private key to use for decryption:
			// - leaf node: use myPrivKeyBytes (the receiver's leaf or pending-update key)
			// - intermediate node: use PathNodePrivKeys[resIdx] (key derived from a previous commit)
			var privKeyToUse []byte
			if treesync.IsLeaf(resIdx) {
				if resIdx != myNodeIdx {
					continue
				}
				privKeyToUse = myPrivKeyBytes
			} else {
				if g.pathNodePrivKeys == nil {
					continue
				}
				privKeyToUse = g.pathNodePrivKeys[resIdx]
				if len(privKeyToUse) == 0 {
					continue
				}
			}

			if m >= len(updatePath.Nodes) || j >= len(updatePath.Nodes[m].EncryptedPathSecrets) {
				return nil, fmt.Errorf("path secret index out of bounds at filtered level %d", m)
			}
			ct := &updatePath.Nodes[m].EncryptedPathSecrets[j]
			psBytes, err := ciphersuite.DecryptWithLabel(
				privKeyToUse,
				"UpdatePathNode",
				gcBytes,
				ct,
				g.cipherSuite,
			)
			if err != nil {
				return nil, fmt.Errorf("decrypting path secret at level %d: %w", level+1, err)
			}

			// Derive forward F-m times to reach commitSecret = pathSecrets[N].
			// While deriving, store private keys for all filtered direct path nodes
			// above m (RFC §12.4.2): these let us decrypt future commits where a
			// sender's ancestor node appears in the copath resolution.
			// RFC §12.4.2: also verify each derived public key matches the published
			// UpdatePathNode.EncryptionKey (Gap 13).
			pathSecret := ciphersuite.NewSecretForCS(g.cipherSuite, psBytes)
			secureZeroBytes(psBytes)
			if g.pathNodePrivKeys == nil {
				g.pathNodePrivKeys = make(map[treesync.NodeIndex][]byte)
			}
			for k := m; k < F; k++ {
				// Store private key for the direct path node at filtered level k.
				// directPath[levels[k]+1] is the node whose key corresponds to pathSecret.
				nodeSecret, nsErr := pathSecret.DeriveSecret(g.cipherSuite, "node")
				if nsErr == nil {
					nodeIdx := directPath[levels[k]+1]
					privKey, pkErr := ciphersuite.DeriveKeyPair(g.cipherSuite, nodeSecret.AsSlice())
					if pkErr == nil {
						// RFC §12.4.2: verify derived public key matches published EncryptionKey.
						if !bytes.Equal(privKey.PublicKey().Bytes(), updatePath.Nodes[k].EncryptionKey) {
							secureZeroSecret(nodeSecret)
							secureZeroSecret(pathSecret)
							return nil, fmt.Errorf("derived public key at path level %d does not match UpdatePath.Nodes[%d].EncryptionKey: %w",
								k, k, ErrInvalidProposal)
						}
						g.setPathNodePrivKey(nodeIdx, privKey.Bytes())
					}
					secureZeroSecret(nodeSecret)
				}
				nextPathSecret, deriveErr := pathSecret.DeriveSecret(g.cipherSuite, "path")
				secureZeroSecret(pathSecret)
				pathSecret = nextPathSecret
				err = deriveErr
				if err != nil {
					return nil, err
				}
			}
			return pathSecret, nil
		}
	}
	return nil, ErrOwnLeafNotFound
}

// MergeCommit applies a received or locally-generated commit to the group state.
//
// RFC 9420 §12.4.2
// This function verifies the commit, applies its proposals, updates the ratchet tree,
// and derives the key schedule for the new epoch.
func (g *Group) MergeCommit(stagedCommit *StagedCommit) error {
	if g.state != StatePendingCommit && g.state != StateOperational {
		return fmt.Errorf("group not in valid state for commit: %w", ErrInvalidGroupState)
	}

	// Epoch validation (RFC 9420 §12.4.1)
	// GroupID validation (RFC 9420 §12.4.1)
	if stagedCommit.authenticatedContent != nil {
		// Validate GroupID
		if !bytes.Equal(stagedCommit.authenticatedContent.Content.GroupID, g.groupContext.GroupID.AsSlice()) {
			return &ErrGroupIDMismatch{
				Got:  stagedCommit.authenticatedContent.Content.GroupID,
				Want: g.groupContext.GroupID.AsSlice(),
			}
		}

		// Validate epoch
		if stagedCommit.authenticatedContent.Content.Epoch != g.groupContext.Epoch.AsUint64() {
			return &ErrEpochMismatch{
				Got:  stagedCommit.authenticatedContent.Content.Epoch,
				Want: g.groupContext.Epoch.AsUint64(),
			}
		}

		// Signature verification for member commits
		// (external commits are already verified when processing the UpdatePath)
		senderType := stagedCommit.authenticatedContent.Content.Sender.Type
		if senderType == framing.SenderTypeMember {
			senderLeafIdx := treesync.LeafIndex(stagedCommit.authenticatedContent.Content.Sender.LeafIndex)
			senderLeaf := g.ratchetTree.GetLeaf(senderLeafIdx)
			if senderLeaf == nil || senderLeaf.LeafData == nil {
				return fmt.Errorf("missing sender signature key for commit verification")
			}

			rawKey := senderLeaf.LeafData.SigKeyBytes()
			if len(rawKey) == 0 {
				return fmt.Errorf("missing sender signature key for commit verification")
			}

			pubKey := ciphersuite.NewMLSSignaturePublicKey(rawKey, g.cipherSuite.SignatureScheme())
			ac := &framing.AuthenticatedContent{
				WireFormat:   stagedCommit.authenticatedContent.WireFormat,
				Content:      stagedCommit.authenticatedContent.Content,
				Auth:         stagedCommit.authenticatedContent.Auth,
				GroupContext: g.groupContext.Marshal(),
			}
			if err := ciphersuite.VerifyWithLabel(pubKey, "FramedContentTBS", ac.MarshalTBS(), stagedCommit.authenticatedContent.Auth.Signature); err != nil {
				return &ErrInvalidSignature{Context: "commit", Err: err}
			}
		}
	}

	// Apply proposals to the ratchet tree
	// RFC §12.4.3.2: for external commits, proposals (including any Remove) must be
	// applied BEFORE adding the external committer's leaf, so the freed slot can be reused.
	senderIdx := g.ownLeafIndex
	isExternalCommit := stagedCommit.authenticatedContent != nil &&
		stagedCommit.authenticatedContent.Content.Sender.Type == framing.SenderTypeNewMemberCommit
	if !isExternalCommit {
		if stagedCommit.authenticatedContent != nil {
			senderIdx = LeafNodeIndex(stagedCommit.authenticatedContent.Content.Sender.LeafIndex)
		}
	}
	// RFC §12.4.2: newly added members must be excluded from copath resolution
	// when decrypting the UpdatePath (same exclusion the committer applied).
	excluded := make(map[treesync.LeafIndex]bool)
	hasGroupContextExtensions := false
	for i, proposal := range stagedCommit.proposals {
		// Use per-proposal sender if available (from ProcessReceivedCommit),
		// otherwise fall back to committer index (self-commit path).
		proposalSender := senderIdx
		if len(stagedCommit.proposalSenders) > i {
			proposalSender = stagedCommit.proposalSenders[i]
		}
		if proposal.Type == ProposalTypeAdd {
			// Apply Add inline so we can capture the assigned leaf index for exclusion.
			addedLeafIdx, err := g.applyAddProposalTracked(proposal.Add)
			if err != nil {
				return fmt.Errorf("applying proposal: %w", err)
			}
			excluded[addedLeafIdx] = true
		} else {
			if err := g.applyProposal(proposal, proposalSender); err != nil {
				return fmt.Errorf("applying proposal: %w", err)
			}
		}
		if proposal.Type == ProposalTypeGroupContextExtensions {
			hasGroupContextExtensions = true
		}
		// RFC §12.4.3.3: if our own Update proposal was committed, the new leaf key
		// (PendingUpdatePrivKey from SelfUpdate) replaces the current MyLeafEncryptionKey.
		if proposal.Type == ProposalTypeUpdate && g.pendingUpdatePrivKey != nil && proposal.Update != nil && proposal.Update.LeafNode != nil {
			ownLeaf := g.ratchetTree.GetLeaf(treesync.LeafIndex(g.ownLeafIndex))
			// This compares public signature keys to detect whether our own update committed.
			if ownLeaf != nil && ownLeaf.LeafData != nil && bytes.Equal(proposal.Update.LeafNode.SignatureKeyBytes, ownLeaf.LeafData.SigKeyBytes()) {
				// RFC §9.2: zero the old HPKE private key before replacing with the new one
				g.setMyLeafEncryptionKey(g.pendingUpdatePrivKey)
				g.pendingUpdatePrivKey = nil
			}
		}
	}

	if hasGroupContextExtensions && g.extensionHandlers != nil {
		if err := g.extensionHandlers.ValidateAll(context.Background(), g.groupContext); err != nil {
			return fmt.Errorf("validating custom group context extensions: %w", err)
		}
	}

	// RFC §12.4.3.2: after proposals are applied, add the external committer's leaf.
	if isExternalCommit {
		if stagedCommit.commit == nil || stagedCommit.commit.Path == nil || stagedCommit.commit.Path.LeafNode == nil {
			return fmt.Errorf("external commit missing update path")
		}
		extLeafIdx, _ := g.ratchetTree.AddLeaf(*stagedCommit.commit.Path.LeafNode)
		senderIdx = LeafNodeIndex(extLeafIdx)
		// Track the external joiner in Members so they can be found by identity later.
		leafNode := stagedCommit.commit.Path.LeafNode
		g.members[senderIdx] = &Member{
			LeafIndex:  senderIdx,
			Credential: leafNode.Credential,
			Active:     true,
		}
	}

	hasReInit := false
	for _, proposal := range stagedCommit.proposals {
		if proposal.Type == ProposalTypeReInit {
			hasReInit = true
			break
		}
	}

	psks, err := g.collectPSKsFromProposals(stagedCommit.proposals)
	if err != nil {
		return fmt.Errorf("collecting PSKs: %w", err)
	}

	// RFC §12.1.3 step 4: truncate trailing blank leaves ONCE after all
	// proposals are applied (not per-Remove). This matches OpenMLS behavior.
	g.ratchetTree.TruncateTrailingBlanks()
	g.ratchetTree = g.ratchetTree.ExpandToPowerOf2()

	// Apply UpdatePath if it exists
	if stagedCommit.commit.Path != nil {
		senderLeafIdx := treesync.LeafIndex(senderIdx)
		leafNodeData := stagedCommit.commit.Path.LeafNode

		// RFC §7.2 + §12.4.2: leaf_node_source MUST be commit (3) in an UpdatePath
		if leafNodeData.LeafNodeSource != 3 {
			return fmt.Errorf("UpdatePath leaf node has leaf_node_source %d, want 3 (commit)",
				leafNodeData.LeafNodeSource)
		}
		// RFC §12.4.2: verify signature of the new committer leaf node (source=commit,
		// TBS includes group_id and leaf_index per RFC §7.2).
		if err := leafNodeData.VerifyWithContext(g.cipherSuite, g.groupContext.GroupID.AsSlice(), uint32(senderLeafIdx)); err != nil {
			return fmt.Errorf("UpdatePath leaf node signature invalid: %w", err)
		}

		// Update the sender leaf
		if err := g.ratchetTree.SetLeaf(senderLeafIdx, *leafNodeData); err != nil {
			return fmt.Errorf("setting sender leaf: %w", err)
		}

		// RFC §12.4.2 step 6: Blank ALL intermediate nodes on the committer's
		// direct path before applying the UpdatePath encryption keys.
		mergeDP := g.ratchetTree.DirectPath(senderLeafIdx)
		for i := 1; i < len(mergeDP); i++ {
			g.ratchetTree.BlankNode(mergeDP[i])
		}

		// Update ancestors with new encryption keys (filtered direct path).
		// Re-compute filtered levels after blanking. Exclude newly added leaves
		// (RFC §12.4.2) so the filtered levels match those used by the committer.
		mergeDP, _, mergeLevels := filteredDirectPathLevels(g.ratchetTree, senderLeafIdx)
		for m, level := range mergeLevels {
			if m >= len(stagedCommit.commit.Path.Nodes) {
				break
			}
			nodeIdx := mergeDP[level+1]
			updateNode := stagedCommit.commit.Path.Nodes[m]
			node := &g.ratchetTree.Nodes[nodeIdx]
			node.EncryptionKey, _ = g.cipherSuite.Curve().NewPublicKey(updateNode.EncryptionKey)
			node.State = treesync.NodeStatePresent
			node.UnmergedLeaves = nil
		}

		// Update PathNodePrivKeys for the sender's direct path nodes:
		// - For the committer themselves: createUpdatePath already populated the keys → no-op.
		// - For receivers: decryptPathSecret derived and stored the new private keys (which
		//   now match the new public keys from UpdatePath), so no action needed either.
		// In both cases, nodes on the sender's direct path that are NOT filtered levels
		// are now BLANK (no public key) → any stale private key for those nodes is useless.
		// Clean them up to avoid confusion.
		if g.pathNodePrivKeys != nil {
			for i, nodeIdx := range mergeDP[1:] { // skip the sender's leaf
				_ = i
				// Only delete if the node is now blank (not a filtered level).
				// Filtered-level nodes have fresh keys stored by createUpdatePath / decryptPathSecret.
				if nodeIdx < treesync.NodeIndex(len(g.ratchetTree.Nodes)) &&
					g.ratchetTree.Nodes[nodeIdx].State != treesync.NodeStatePresent {
					// RFC §9.2: zero key bytes before removing from map (forward secrecy)
					g.deletePathNodePrivKey(nodeIdx)
				}
			}
		}

		// Compute parent hashes top-down (RFC §7.9). Must run for ALL commits,
		// including external commits, so that TreeHash() returns the correct value.
		if len(mergeDP) > 1 {
			rootIdx := g.ratchetTree.Root()
			g.ratchetTree.Nodes[rootIdx].ParentHash = []byte{}

			for i := len(mergeDP) - 2; i >= 0; i-- {
				nodeIdx := mergeDP[i]
				parentIdx := mergeDP[i+1]
				parent := &g.ratchetTree.Nodes[parentIdx]

				// RFC §7.9: blank/empty parent → pass through; present → compute.
				var ph []byte
				if parent.State == treesync.NodeStatePresent {
					var parentKey []byte
					if parent.EncryptionKey != nil {
						parentKey = parent.EncryptionKey.Bytes()
					}
					siblingIdx := g.ratchetTree.GetSibling(nodeIdx)
					siblingHash := g.ratchetTree.HashNode(siblingIdx)
					ph = treesync.ComputeParentHash(parentKey, parent.ParentHash, siblingHash, g.cipherSuite.HashFunction())
				} else {
					ph = parent.ParentHash
				}

				// Store parent hash in ALL nodes of the direct path (including the leaf)
				g.ratchetTree.Nodes[nodeIdx].ParentHash = ph
			}

			// RFC §7.9.2: verify the sender's signed LeafData.ParentHash against
			// what we derive from the (potentially untrusted) UpdatePath keys.
			// This catches corruption of UpdatePath.Nodes[*].EncryptionKey because
			// the sender's LeafNode is signed with the original keys.
			// Only run when there was an UpdatePath (commit.Path != nil, i.e. we are
			// inside this block). Do NOT run when force_path=false (no path) since
			// parent_hash fields of blank nodes carry prior-epoch values.
			if err := g.ratchetTree.VerifyParentHashes(senderLeafIdx); err != nil {
				return fmt.Errorf("parent hash verification failed after UpdatePath merge: %w", err)
			}
		}
	}

	// Recompute TreeHash from treesync
	oldEpoch := g.epoch.AsUint64()
	oldEpochSecrets := g.epochSecrets
	oldSecretTree := g.secretTree
	oldRatchetTree := g.ratchetTree
	oldGroupContext := g.groupContext.Clone()
	oldCipherSuite := g.cipherSuite

	treeHash := g.ratchetTree.TreeHash()

	// Compute ConfirmedTranscriptHash nuevo
	cthi, err := framing.NewConfirmedTranscriptHashInput(stagedCommit.authenticatedContent)
	if err != nil {
		return fmt.Errorf("creating transcript hash input: %w", err)
	}

	confirmedTranscriptHash, err := cthi.Compute(
		g.cipherSuite,
		g.interimTranscriptHash,
	)
	if err != nil {
		return fmt.Errorf("calculating confirmed transcript hash: %w", err)
	}
	// Compute InterimTranscriptHash nuevo
	itHashInput := &framing.InterimTranscriptHashInput{
		ConfirmationTag: stagedCommit.authenticatedContent.Auth.ConfirmationTag,
	}

	interimTranscriptHash := itHashInput.Compute(
		g.cipherSuite,
		confirmedTranscriptHash,
	)

	// Update GroupContext (RFC §8.1)
	g.groupContext.IncrementEpoch()
	g.groupContext.UpdateTreeHash(treeHash)
	g.groupContext.UpdateConfirmedTranscriptHash(confirmedTranscriptHash)

	// Also update Group directly
	g.epoch = g.groupContext.Epoch
	g.interimTranscriptHash = interimTranscriptHash
	g.confirmationTag = stagedCommit.authenticatedContent.Auth.ConfirmationTag

	// Advance key schedule to new EpochSecrets
	if stagedCommit.precomputedEpochSecrets != nil {
		// Committer: use precomputed epoch secrets from Commit()

		// Cache current epoch secrets for out-of-order decryption before replacing.
		g.cacheOldEpoch(oldEpoch, oldEpochSecrets, oldSecretTree, oldRatchetTree, oldGroupContext, oldCipherSuite)

		g.epochSecrets = stagedCommit.precomputedEpochSecrets
	} else {
		// Receiver: derive epoch secrets from init_secret of current epoch
		initSecretForNewEpoch := g.epochSecrets.InitSecret
		for _, proposal := range stagedCommit.proposals {
			if proposal.Type != ProposalTypeExternalInit || proposal.ExternalInit == nil {
				continue
			}
			externalPriv, deriveErr := ciphersuite.DeriveKeyPair(
				g.cipherSuite,
				g.epochSecrets.ExternalSecret.AsSlice(),
			)
			if deriveErr != nil {
				return fmt.Errorf("deriving external key pair: %w", deriveErr)
			}

			sharedSecretBytes, decapErr := ciphersuite.DecapToBytes(
				proposal.ExternalInit.KemOutput,
				externalPriv.Bytes(),
				g.cipherSuite,
			)
			if decapErr != nil {
				return fmt.Errorf("HPKE decap for external commit: %w", decapErr)
			}

			initSecretForNewEpoch = ciphersuite.NewSecretForCS(g.cipherSuite, sharedSecretBytes)
			break
		}

		var commitSecret *ciphersuite.Secret
		if stagedCommit.commit != nil && stagedCommit.commit.Path != nil {
			commitSecret = stagedCommit.rootPathSecret
		} else {
			commitSecret = ciphersuite.ZeroSecretCS(g.cipherSuite)
		}

		newGCBytes := g.groupContext.Marshal()
		// Snapshot values before key schedule zeroes them (for debugging)
		dbgInitSecret := append([]byte(nil), initSecretForNewEpoch.AsSlice()...)
		var dbgCommitSecret []byte
		if commitSecret != nil {
			dbgCommitSecret = append([]byte(nil), commitSecret.AsSlice()...)
		}
		// Derive epoch secrets for the new epoch
		newKS := schedule.NewKeySchedule(g.cipherSuite, initSecretForNewEpoch)
		newKS.SetCommitSecret(commitSecret)
		if _, err = newKS.ComputeJoinerSecret(newGCBytes); err != nil {
			return fmt.Errorf("computing joiner secret: %w", err)
		}
		if _, err = newKS.ComputePskSecret(psks); err != nil {
			return fmt.Errorf("computing psk secret: %w", err)
		}
		if _, err = newKS.ComputeEpochSecret(newGCBytes); err != nil {
			return fmt.Errorf("computing epoch secret: %w", err)
		}
		var newEpochSecrets *schedule.EpochSecrets
		newEpochSecrets, err = newKS.DeriveEpochSecrets()
		if err != nil {
			return fmt.Errorf("deriving epoch secrets: %w", err)
		}

		// Verify commit confirmation_tag (RFC §12.4.2)
		expectedTag := schedule.ComputeConfirmationTag(
			g.cipherSuite,
			newEpochSecrets.ConfirmationKey.AsSlice(),
			confirmedTranscriptHash,
		)
		if !ciphersuite.EqualCT(expectedTag, stagedCommit.authenticatedContent.Auth.ConfirmationTag) {
			return fmt.Errorf("confirmation tag mismatch [leaf=%d interimHash=%x confirmedHash=%x treeHash=%x initSecret=%x commitSecret=%x]",
				g.ownLeafIndex,
				g.interimTranscriptHash,
				confirmedTranscriptHash,
				treeHash,
				dbgInitSecret,
				dbgCommitSecret,
			)
		}

		// Cache current epoch secrets for out-of-order decryption before replacing.
		g.cacheOldEpoch(oldEpoch, oldEpochSecrets, oldSecretTree, oldRatchetTree, oldGroupContext, oldCipherSuite)

		g.epochSecrets = newEpochSecrets
	}
	// Initialize key schedule for the next epoch
	g.keySchedule = schedule.NewKeySchedule(g.cipherSuite, g.epochSecrets.InitSecret)

	// Update secret tree for new epoch
	g.secretTree, err = secrettree.NewTree(g.epochSecrets.EncryptionSecret, g.ratchetTree.NumLeaves, g.cipherSuite)
	if err != nil {
		return fmt.Errorf("updating secret tree: %w", err)
	}

	// Cache resumption secret for this epoch (keyed by group_id + epoch)
	// so future resumption PSK proposals can resolve it.
	if g.epochSecrets.ResumptionSecret != nil {
		rKey := ResumptionPskCacheKey(g.groupContext.GroupID.AsSlice(), g.groupContext.Epoch.AsUint64())
		secret := append([]byte(nil), g.epochSecrets.ResumptionSecret.AsSlice()...)
		g.pskMu.Lock()
		if g.cachedPsks == nil {
			g.cachedPsks = make(map[string][]byte)
		}
		g.cachedPsks[rKey] = secret
		g.pskMu.Unlock()
	}

	// Save committed proposals before clearing (used by HandlePendingReInitCommit).
	g.lastCommittedProposals = stagedCommit.proposals

	// Apply the new leaf HPKE private key generated during Commit() now that the
	// commit is confirmed. pendingLeafKey is nil for receiver-side MergeCommits.
	// setMyLeafEncryptionKey takes ownership of the slice (no copy), so we must
	// NOT zero it here — that would also zero myLeafEncryptionKey via the shared
	// backing array, breaking decryption of future path secrets addressed to us.
	if g.pendingLeafKey != nil {
		g.setMyLeafEncryptionKey(g.pendingLeafKey)
		g.pendingLeafKey = nil
	}

	// Clean up state
	g.proposals.Clear()
	g.proposalByRef = make(map[string]*Proposal)
	g.pendingCommit = nil
	if hasReInit {
		g.state = StateInactive
	} else {
		g.state = StateOperational
	}
	return nil
}

// collectPSKsFromProposals resolves PSK values for all PreSharedKey proposals in the list.
// Used by both CommitWithContext (sender) and MergeCommit (receiver) to populate the key schedule.
func (g *Group) collectPSKsFromProposals(proposals []*Proposal) ([]schedule.Psk, error) {
	var psks []schedule.Psk
	for _, proposal := range proposals {
		if proposal.Type != ProposalTypePreSharedKey || proposal.PreSharedKey == nil {
			continue
		}
		pid := proposal.PreSharedKey.PskID
		var (
			pskBytes []byte
			err      error
			ok       bool
		)
		if pid.PskType == 2 { // Resumption PSK
			resumptionKey := ResumptionPskCacheKey(pid.PskGroupID, pid.PskEpoch)
			pskBytes, ok = g.cachedPsks[resumptionKey]
			if !ok {
				if g.PSKStore != nil {
					pskBytes, err = NewPSKResolver(g.PSKStore).ResolvePSK(&pid)
					if err != nil {
						return nil, fmt.Errorf("resolving resumption PSK: %w", err)
					}
				} else {
					return nil, fmt.Errorf("missing resumption PSK for group=%x epoch=%d", pid.PskGroupID, pid.PskEpoch)
				}
			}
			psks = append(psks, schedule.Psk{
				Psk:        pskBytes,
				PskID:      pid.ID,
				PskNonce:   pid.Nonce,
				PskType:    schedule.PskType(pid.PskType),
				Usage:      pid.Usage,
				PskGroupID: pid.PskGroupID,
				PskEpoch:   pid.PskEpoch,
			})
		} else { // External or Branch PSK
			pskBytes, ok = g.cachedPsks[string(pid.ID)]
			if !ok && g.PSKStore != nil {
				pskBytes, err = g.PSKStore.GetPSK(pid.ID)
				if err != nil {
					return nil, fmt.Errorf("resolving PSK from store: %w", err)
				}
			} else if !ok {
				return nil, fmt.Errorf("missing PSK for proposal: %x", pid.ID)
			}
			psks = append(psks, schedule.Psk{
				Psk:      pskBytes,
				PskID:    pid.ID,
				PskNonce: pid.Nonce,
				PskType:  schedule.PskType(pid.PskType),
				Usage:    pid.Usage,
			})
		}
	}
	return psks, nil
}

// ResumptionPskCacheKey builds a compound cache key for resumption PSKs
// from (group_id, epoch) per RFC 9420 §8.4.
func ResumptionPskCacheKey(groupID []byte, epoch uint64) string {
	buf := make([]byte, len(groupID)+8)
	copy(buf, groupID)
	buf[len(groupID)] = byte(epoch >> 56)
	buf[len(groupID)+1] = byte(epoch >> 48)
	buf[len(groupID)+2] = byte(epoch >> 40)
	buf[len(groupID)+3] = byte(epoch >> 32)
	buf[len(groupID)+4] = byte(epoch >> 24)
	buf[len(groupID)+5] = byte(epoch >> 16)
	buf[len(groupID)+6] = byte(epoch >> 8)
	buf[len(groupID)+7] = byte(epoch)
	return string(buf)
}

// ProcessPublicMessage processes a received PublicMessage (RFC 9420 §6).
//
// This handles proposals and commits sent as public messages, verifying
// signatures and membership tags before processing the content.
func (g *Group) ProcessPublicMessage(pm *framing.PublicMessage) error {
	if pm == nil {
		return fmt.Errorf("public message is nil")
	}

	if err := g.VerifyPublicMessage(pm); err != nil {
		return err
	}

	switch pm.Content.ContentType() {
	case framing.ContentTypeProposal:
		sender := LeafNodeIndex(pm.Content.Sender.LeafIndex)
		if pm.Content.Sender.Type == framing.SenderTypeExternal {
			sender = LeafNodeIndex(g.ratchetTree.NumLeaves + pm.Content.Sender.SenderIndex)
		}
		// Create AuthenticatedContent for validation
		ac := &framing.AuthenticatedContent{
			WireFormat:   framing.WireFormatPublicMessage,
			Content:      pm.Content,
			Auth:         pm.Auth,
			GroupContext: g.groupContext.Marshal(),
		}
		// Use shared function to process the proposal
		return g.processProposalContent(ac, sender)
	case framing.ContentTypeCommit:
		ac := &framing.AuthenticatedContent{
			WireFormat:   framing.WireFormatPublicMessage,
			Content:      pm.Content,
			Auth:         pm.Auth,
			GroupContext: g.groupContext.Marshal(),
		}
		senderLeafIdx := treesync.LeafIndex(pm.Content.Sender.LeafIndex)
		return g.ProcessReceivedCommit(ac, senderLeafIdx, g.myLeafEncryptionKey)
	case framing.ContentTypeApplication:
		return fmt.Errorf("public application messages are not supported")
	default:
		return fmt.Errorf("unsupported public message content type: %d", pm.Content.ContentType())
	}
}

// ProcessPrivateMessage processes a PrivateMessage (proposal or commit) (RFC 9420 §6.3, §12.4).
// Extracts the sender from the encrypted MLSSenderData, verifies the signature, and processes the content.
func (g *Group) ProcessPrivateMessage(pm *framing.PrivateMessage) error {
	if pm == nil {
		return fmt.Errorf("private message is nil")
	}

	if g.epochSecrets == nil || g.epochSecrets.SenderDataSecret == nil {
		return fmt.Errorf("sender_data_secret not available")
	}

	// RFC 9420 §6: reject messages from a different epoch.
	if pm.Epoch != g.groupContext.Epoch.AsUint64() {
		return fmt.Errorf("wrong epoch: got %d, want %d", pm.Epoch, g.groupContext.Epoch.AsUint64())
	}

	// decrypt the message and get sender from MLSSenderData
	ac, senderLeafIdx, err := g.decryptPrivateMessage(pm)
	if err != nil {
		return fmt.Errorf("decrypting private message: %w", err)
	}

	// process according to content type
	switch ac.Content.ContentType() {
	case framing.ContentTypeProposal:
		return g.processProposalContent(ac, LeafNodeIndex(senderLeafIdx))
	case framing.ContentTypeCommit:
		return g.ProcessReceivedCommit(ac, senderLeafIdx, g.myLeafEncryptionKey)
	default:
		return fmt.Errorf("private message with content type %d is not a proposal or commit", ac.Content.ContentType())
	}
}

// decryptPrivateMessage decrypts a PrivateMessage and returns the AuthenticatedContent
// along with the sender leaf index extracted from the MLSSenderData.
func (g *Group) decryptPrivateMessage(pm *framing.PrivateMessage) (*framing.AuthenticatedContent, treesync.LeafIndex, error) {
	// decrypt without verifying signature (sender encrypted in MLSSenderData, still unknown)
	ac, err := framing.Decrypt(pm, framing.DecryptParams{
		CipherSuite:      g.cipherSuite,
		SenderDataSecret: g.epochSecrets.SenderDataSecret,
		SecretTree:       g.secretTree,
		SigPubKey:        nil,
		GroupContext:     g.groupContext.Marshal(),
	})
	if err != nil {
		return nil, 0, err
	}

	// extract sender leaf index from FramedContent (which came from MLSSenderData)
	senderLeafIdx := treesync.LeafIndex(ac.Content.Sender.LeafIndex)

	// verify that the sender exists in the RatchetTree and is active
	senderLeaf := g.ratchetTree.GetLeaf(senderLeafIdx)
	if senderLeaf == nil || senderLeaf.State != treesync.NodeStatePresent {
		return nil, 0, fmt.Errorf("sender %d is not an active member", senderLeafIdx)
	}

	// RFC 9420 §6.1: verify the FramedContent signature with the sender's public key.
	rawKey := senderLeaf.LeafData.SigKeyBytes()
	if len(rawKey) == 0 {
		return nil, 0, fmt.Errorf("missing sender signature key")
	}
	pubKey := ciphersuite.NewMLSSignaturePublicKey(rawKey, g.cipherSuite.SignatureScheme())
	if err := ciphersuite.VerifyWithLabel(pubKey, "FramedContentTBS", ac.MarshalTBS(), ac.Auth.Signature); err != nil {
		return nil, 0, fmt.Errorf("private message signature invalid: %w", err)
	}

	return ac, senderLeafIdx, nil
}

// processProposalContent processes the content of a proposal (shared between Public and Private).
func (g *Group) processProposalContent(ac *framing.AuthenticatedContent, sender LeafNodeIndex) error {
	body, ok := ac.Content.Body.(framing.ProposalBody)
	if !ok {
		return fmt.Errorf("invalid proposal body")
	}

	proposal, err := UnmarshalProposal(body.Data)
	if err != nil {
		return fmt.Errorf("unmarshaling proposal: %w", err)
	}

	// RFC 9420 §12.2: Validate proposal immediately upon receiving it
	switch proposal.Type {
	case ProposalTypeAdd:
		if proposal.Add != nil && proposal.Add.KeyPackage != nil && proposal.Add.KeyPackage.LeafNode != nil {
			if err := g.validateAddKeyPackageUniqueness(proposal.Add.KeyPackage); err != nil {
				return err
			}
			// RFC §12.2: Verify KeyPackage signature
			if err := proposal.Add.KeyPackage.Verify(g.cipherSuite); err != nil {
				return fmt.Errorf("add proposal keypackage signature invalid: %w", err)
			}
			// RFC §7.3, §12.2: full LeafNode validation (key_package source, lifetime,
			// capabilities, credential, signature). Use ValidateLeafNode since Add
			// proposals carry source=key_package (no group context in TBS).
			leafData := keyPackageLeafToTreeSync(proposal.Add.KeyPackage.LeafNode)
			if err := treesync.ValidateLeafNode(leafData, g.cipherSuite); err != nil {
				return fmt.Errorf("invalid add proposal leaf node: %w", err)
			}
			if err := validateCapabilitiesCompatible(g.cipherSuite, leafData.Capabilities, nil); err != nil {
				return fmt.Errorf("invalid add proposal capabilities: %w", err)
			}
		}
	case ProposalTypeUpdate:
		// RFC §12.2: Verify that sender is an active member
		senderLeaf := g.ratchetTree.GetLeaf(treesync.LeafIndex(sender))
		if senderLeaf == nil || senderLeaf.State != treesync.NodeStatePresent {
			return fmt.Errorf("update proposal sender %d is not an active member", sender)
		}
		if proposal.Update != nil && proposal.Update.LeafNode != nil {
			// RFC §7.3, §12.2: full LeafNode validation with group context (source=update).
			leafData := keyPackageLeafToTreeSync(proposal.Update.LeafNode)
			if err := treesync.ValidateLeafNodeWithContext(leafData, g.cipherSuite, g.groupContext.GroupID.AsSlice(), uint32(sender)); err != nil {
				return fmt.Errorf("invalid update proposal leaf node: %w", err)
			}
			if err := validateCapabilitiesCompatible(g.cipherSuite, leafData.Capabilities, nil); err != nil {
				return fmt.Errorf("invalid update proposal capabilities: %w", err)
			}
		}
	}

	// RFC 9420 §12.4: ProposalRef = RefHash("MLS 1.0 Proposal Reference", Marshal(AuthenticatedContent))
	// WireFormat must match how the proposal was sent (Public or Private).
	acForRef := &framing.AuthenticatedContent{
		WireFormat: ac.WireFormat,
		Content:    ac.Content,
		Auth:       ac.Auth,
	}
	refBytes := acForRef.Marshal()
	g.StoreProposal(proposal, sender, refBytes)
	return nil
}

// applyProposal applies a single proposal to the group state.
func (g *Group) applyProposal(proposal *Proposal, senderIdx LeafNodeIndex) error {
	switch proposal.Type {
	case ProposalTypeAdd:
		return g.applyAddProposal(proposal.Add)
	case ProposalTypeUpdate:
		return g.applyUpdateProposal(proposal.Update, senderIdx)
	case ProposalTypeRemove:
		return g.applyRemoveProposal(proposal.Remove)
	case ProposalTypePreSharedKey:
		// PSK proposals affect key schedule only; no tree modification.
		return nil
	case ProposalTypeExternalInit:
		return nil
	case ProposalTypeReInit:
		return nil
	case ProposalTypeGroupContextExtensions:
		// GroupContextExtensions proposals update group context extensions.
		// RFC 9420 §12.4.2: Apply GCE to the group context.
		if proposal.GroupContextExtensions != nil {
			exts := proposal.GroupContextExtensions.Extensions
			if exts == nil {
				exts = []Extension{}
			}
			g.groupContext.Extensions = exts
		}
		return nil
	default:
		return fmt.Errorf("unsupported proposal type: %d", proposal.Type)
	}
}

// applyAddProposal applies an Add proposal.
// RFC 9420 §12.4.2: The new member's LeafNode from the KeyPackage is added to the tree.
// We use keyPackageLeafToTreeSync to ensure consistency with applyProposalToTree.
func (g *Group) applyAddProposal(add *AddProposal) error {
	_, err := g.applyAddProposalTracked(add)
	return err
}

// applyAddProposalTracked applies an Add proposal and returns the assigned leaf index.
// Used in MergeCommit to build the exclusion set for filteredDirectPathLevelsExcluding.
func (g *Group) applyAddProposalTracked(add *AddProposal) (treesync.LeafIndex, error) {
	if add == nil {
		return 0, ErrNilAddProposal
	}
	if add.KeyPackage == nil {
		return 0, ErrNilKeyPackage
	}

	// Validate KeyPackage
	if err := add.KeyPackage.Validate(); err != nil {
		return 0, fmt.Errorf("invalid key package: %w", err)
	}
	if add.KeyPackage.LeafNode == nil {
		return 0, fmt.Errorf("invalid key package leaf node")
	}

	// Use keyPackageLeafToTreeSync for consistency with applyProposalToTree.
	// This correctly uses LeafNode.EncryptionKey (not KeyPackage.InitKey).
	leafData := keyPackageLeafToTreeSync(add.KeyPackage.LeafNode)
	if err := leafData.Validate(); err != nil {
		return 0, fmt.Errorf("invalid add leaf node: %w", err)
	}

	leafIdx, _ := g.ratchetTree.AddLeaf(*leafData)
	leafIndex := LeafNodeIndex(leafIdx)

	// Add to Members
	g.members[leafIndex] = &Member{
		LeafIndex:  leafIndex,
		KeyPackage: add.KeyPackage,
		Credential: add.KeyPackage.LeafNode.Credential,
		Active:     true,
	}

	return leafIdx, nil
}

// applyUpdateProposal applies an Update proposal.
// RFC 9420 §12.4.2: Update replaces the sender's leaf and blanks the direct path ancestors.
// Must match behavior of applyProposalToTree.
func (g *Group) applyUpdateProposal(update *UpdateProposal, senderIdx LeafNodeIndex) error {
	if update == nil || update.LeafNode == nil {
		return fmt.Errorf("invalid Update proposal")
	}
	leafData := keyPackageLeafToTreeSync(update.LeafNode)
	if err := leafData.Validate(); err != nil {
		return fmt.Errorf("invalid update leaf node: %w", err)
	}

	leafIdx := treesync.LeafIndex(senderIdx)
	if err := g.ratchetTree.SetLeaf(leafIdx, *leafData); err != nil {
		return err
	}

	// Blank the direct path ancestors (skip the leaf node itself at index 0).
	path := g.ratchetTree.DirectPath(leafIdx)
	for i := 1; i < len(path); i++ {
		g.ratchetTree.BlankNode(path[i])
	}

	return nil
}

// applyRemoveProposal applies a Remove proposal.
// RFC 9420 §12.4.2: Remove blanks the leaf and its entire direct path.
// Must match behavior of applyProposalToTree.
func (g *Group) applyRemoveProposal(remove *RemoveProposal) error {
	if remove == nil {
		return fmt.Errorf("invalid Remove proposal")
	}

	// Blank the leaf and its entire direct path (matches applyProposalToTree).
	removedLeaf := treesync.LeafIndex(remove.Removed)
	for _, nodeIdx := range g.ratchetTree.DirectPath(removedLeaf) {
		g.ratchetTree.BlankNode(nodeIdx)
	}
	// NOTE: Do NOT truncate here. Truncation is deferred until after all
	// proposals are applied (matching OpenMLS behavior). See applyProposalToTree.

	// Mark member as inactive
	if member, ok := g.members[remove.Removed]; ok {
		member.Active = false
	}

	return nil
}

// GetMember returns a member by leaf index.
func (g *Group) GetMember(leafIndex LeafNodeIndex) (*Member, bool) {
	member, ok := g.members[leafIndex]
	return member, ok
}

// GetMembers returns all active members.
func (g *Group) GetMembers() []*Member {
	members := make([]*Member, 0)
	for _, member := range g.members {
		if member.Active {
			members = append(members, member)
		}
	}
	return members
}

// MemberSigningKey returns the current signature public key for the given leaf.
func (g *Group) MemberSigningKey(leafIndex LeafNodeIndex) []byte {
	if g == nil || g.ratchetTree == nil {
		return nil
	}
	leaf := g.ratchetTree.GetLeaf(treesync.LeafIndex(leafIndex))
	if leaf == nil || leaf.State != treesync.NodeStatePresent || leaf.LeafData == nil {
		return nil
	}
	return append([]byte(nil), leaf.LeafData.SigKeyBytes()...)
}

// MemberCount returns the number of active members.
func (g *Group) MemberCount() int {
	count := 0
	for _, member := range g.members {
		if member.Active {
			count++
		}
	}
	return count
}

// State returns the current state of the group.
func (g *Group) State() GroupState {
	return g.state
}

// StoredProposals returns a copy of the currently stored proposals.
func (g *Group) StoredProposals() []StoredProposal {
	if g == nil || g.proposals == nil {
		return nil
	}
	out := make([]StoredProposal, len(g.proposals.Proposals))
	copy(out, g.proposals.Proposals)
	return out
}

// EpochAuthenticator returns the epoch authenticator bytes (RFC 9420 §8).
//
// In this implementation, epoch_authenticator maps to authentication_secret.
func (g *Group) EpochAuthenticator() []byte {
	if g == nil || g.epochSecrets == nil || g.epochSecrets.AuthenticationSecret == nil {
		return nil
	}
	return append([]byte(nil), g.epochSecrets.AuthenticationSecret.AsSlice()...)
}

// NewGroupFromReInit creates a successor group from a ReInit proposal.
// oldGroupID must be the GroupID of the group that sent the ReInit proposal
// (RFC §12.4.4: the resumption PSK ID references the old group, not the new one).
func NewGroupFromReInit(
	reInit *ReInitProposal,
	resumptionSecret *ciphersuite.Secret,
	oldGroupID []byte,
	myKP *keypackages.KeyPackage,
	myPriv *keypackages.KeyPackagePrivateKeys,
	opts ...GroupOption,
) (*Group, error) {
	cfg := groupConfig{}
	for _, opt := range opts {
		if opt != nil {
			opt(&cfg)
		}
	}

	if reInit == nil {
		return nil, fmt.Errorf("reinit proposal is nil")
	}
	if resumptionSecret == nil {
		return nil, fmt.Errorf("resumption secret is nil")
	}
	if len(oldGroupID) == 0 {
		return nil, fmt.Errorf("oldGroupID must not be nil or empty")
	}
	if myKP == nil || myPriv == nil {
		return nil, fmt.Errorf("key package/private keys are nil")
	}
	if myKP.LeafNode == nil {
		return nil, fmt.Errorf("key package leaf node is nil")
	}

	cs := reInit.CipherSuite
	ratchetTree := treesync.NewRatchetTree(1, cs)
	leafData := treesync.LeafNodeData{
		EncryptionKey:   myKP.LeafNode.EncryptionKey, // RFC §10.1: use LeafNode.encryption_key for TreeKEM
		SignatureKey:    myKP.LeafNode.SignatureKey,
		SignatureKeyRaw: append([]byte(nil), myKP.LeafNode.SignatureKeyBytes...),
		Credential:      myKP.LeafNode.Credential,
		Capabilities:    toTreeSyncCapabilities(myKP.LeafNode.Capabilities),
		Lifetime:        keyPackageToTreeSyncLifetime(myKP.LeafNode.Lifetime),
		Extensions:      keyPackageExtensionsToTreeSync(myKP.LeafNode.Extensions),
		LeafNodeSource:  1,
		ParentHash:      append([]byte(nil), myKP.LeafNode.ParentHash...),
		Signature:       append([]byte(nil), myKP.LeafNode.Signature...),
	}
	if leafData.Capabilities == nil {
		leafData.Capabilities = &treesync.LeafNodeCapabilities{}
	}
	if err := leafData.Validate(); err != nil {
		return nil, fmt.Errorf("invalid reinit leaf node: %w", err)
	}
	_, _ = ratchetTree.AddLeaf(leafData)

	groupExtensions := cloneExtensions(reInit.Extensions)
	if cfg.extensions != nil {
		groupExtensions = cloneExtensions(cfg.extensions)
	}
	if groupExtensions == nil {
		groupExtensions = []Extension{}
	}

	groupContext := &GroupContext{
		Version:                 reInit.Version,
		CipherSuite:             cs,
		GroupID:                 NewGroupID(reInit.GroupID),
		Epoch:                   NewGroupEpoch(0),
		TreeHash:                ratchetTree.TreeHash(),
		ConfirmedTranscriptHash: []byte{},
		Extensions:              groupExtensions,
	}

	initSecret := ciphersuite.ZeroSecretCS(cs)
	keySchedule := schedule.NewKeySchedule(cs, initSecret)
	commitSecret := ciphersuite.ZeroSecretCS(cs)
	keySchedule.SetCommitSecret(commitSecret)

	groupContextBytes := groupContext.Marshal()
	if _, err := keySchedule.ComputeJoinerSecret(groupContextBytes); err != nil {
		return nil, fmt.Errorf("computing joiner secret: %w", err)
	}

	pskNonce := make([]byte, cs.HashLength()) // RFC §8.4: fresh random nonce of length KDF.Nh
	if _, err := rand.Read(pskNonce); err != nil {
		return nil, fmt.Errorf("generating reinit psk_nonce: %w", err)
	}
	resumptionPsk := schedule.Psk{
		PskType:  schedule.PskTypeResumption,
		PskID:    oldGroupID,
		PskNonce: pskNonce,
		Psk:      resumptionSecret.AsSlice(),
	}
	if _, err := keySchedule.ComputePskSecret([]schedule.Psk{resumptionPsk}); err != nil {
		return nil, fmt.Errorf("computing reinit psk secret: %w", err)
	}
	if _, err := keySchedule.ComputeEpochSecret(groupContextBytes); err != nil {
		return nil, fmt.Errorf("computing reinit epoch secret: %w", err)
	}
	epochSecrets, err := keySchedule.DeriveEpochSecrets()
	if err != nil {
		return nil, fmt.Errorf("deriving reinit epoch secrets: %w", err)
	}
	group := &Group{
		groupID:               groupContext.GroupID,
		epoch:                 groupContext.Epoch,
		cipherSuite:           cs,
		groupContext:          groupContext,
		ratchetTree:           ratchetTree,
		ownLeafIndex:          NewLeafNodeIndex(0),
		epochSecrets:          epochSecrets,
		proposals:             NewProposalStore(),
		proposalByRef:         make(map[string]*Proposal),
		keySchedule:           keySchedule,
		interimTranscriptHash: []byte{},
		members:               make(map[LeafNodeIndex]*Member),
		state:                 StateOperational,
		cachedPsks:            make(map[string][]byte),
		PSKStore:              cfg.pskStore,
		paddingSize:           cfg.paddingSize,
		extensionHandlers:     cfg.extensionHandlers,
	}
	group.cachedPsks[string(reInit.GroupID)] = resumptionSecret.AsSlice()
	group.secretTree, err = secrettree.NewTree(epochSecrets.EncryptionSecret, ratchetTree.NumLeaves, cs)
	if err != nil {
		return nil, fmt.Errorf("initializing secret tree: %w", err)
	}
	group.members[NewLeafNodeIndex(0)] = &Member{
		LeafIndex:  NewLeafNodeIndex(0),
		KeyPackage: myKP,
		Credential: myKP.LeafNode.Credential,
		Active:     true,
	}
	return group, nil
}

// GetGroupInfo returns a signed GroupInfo for the current epoch (RFC 9420 §12.4.3.2).
func (g *Group) GetGroupInfo(
	signerPrivKey *ciphersuite.SignaturePrivateKey,
) (*GroupInfo, error) {
	if g.state != StateOperational {
		return nil, fmt.Errorf("group not operational")
	}
	return g.buildSignedGroupInfo(signerPrivKey)
}

// GetGroupInfoWithOptions returns a signed GroupInfo for the current epoch with
// customizable extension inclusion.
func (g *Group) GetGroupInfoWithOptions(
	signerPrivKey *ciphersuite.SignaturePrivateKey,
	opts ...GroupInfoOption,
) (*GroupInfo, error) {
	if g.state != StateOperational {
		return nil, fmt.Errorf("group not operational")
	}
	return g.buildSignedGroupInfo(signerPrivKey, opts...)
}

type groupInfoConfig struct {
	includeRatchetTree bool
	includeExternalPub bool
}

func defaultGroupInfoConfig() groupInfoConfig {
	return groupInfoConfig{includeRatchetTree: true, includeExternalPub: true}
}

// GroupInfoOption configures GroupInfo serialization behavior.
type GroupInfoOption func(*groupInfoConfig)

// WithRatchetTree controls inclusion of the ratchet_tree extension.
func WithRatchetTree(include bool) GroupInfoOption {
	return func(cfg *groupInfoConfig) {
		cfg.includeRatchetTree = include
	}
}

// WithExternalPub controls inclusion of the external_pub extension.
func WithExternalPub(include bool) GroupInfoOption {
	return func(cfg *groupInfoConfig) {
		cfg.includeExternalPub = include
	}
}

// GroupInfoOptions controls optional extensions in GroupInfo serialization.
//
// Deprecated: use GroupInfoOption values (WithRatchetTree/WithExternalPub).
type GroupInfoOptions struct {
	IncludeRatchetTree *bool
	IncludeExternalPub *bool
}

func (g *Group) buildSignedGroupInfo(
	signerPrivKey *ciphersuite.SignaturePrivateKey,
	opts ...GroupInfoOption,
) (*GroupInfo, error) {
	cfg := defaultGroupInfoConfig()
	for _, opt := range opts {
		if opt != nil {
			opt(&cfg)
		}
	}
	if signerPrivKey == nil {
		return nil, fmt.Errorf("signer private key is nil")
	}

	extensions := cloneExtensions(g.groupContext.Extensions)

	groupInfo := &GroupInfo{
		GroupContext:    g.groupContext,
		Extensions:      extensions,
		ConfirmationTag: g.confirmationTag,
		Signer:          g.ownLeafIndex,
		RatchetTree:     g.ratchetTree,
	}

	// ratchet_tree extension (RFC 9420 §12.4.3.3) — use RFC interoperable format.
	// Required in Welcome messages so joiners can instantiate the group.
	if cfg.includeRatchetTree {
		groupInfo.Extensions = append(groupInfo.Extensions, Extension{
			Type: mlsext.ExtensionTypeRatchetTree,
			Data: g.ratchetTree.MarshalTreeRFC(),
		})
	}

	// external_pub extension (RFC 9420 §11.2.4) — used for external commits.
	// Applications that don't support external commits (e.g., DAVE) may omit this.
	if cfg.includeExternalPub {
		externalPriv, err := ciphersuite.DeriveKeyPair(
			g.cipherSuite,
			g.epochSecrets.ExternalSecret.AsSlice(),
		)
		if err != nil {
			return nil, fmt.Errorf("deriving external key pair: %w", err)
		}
		// RFC 9420 §11.2.4: HPKEPublicKey is VLBytes, so the extension data
		// must be VL-prefixed key bytes (not raw bytes).
		extPubW := tls.NewWriter()
		extPubW.WriteVLBytes(externalPriv.PublicKey().Bytes())
		groupInfo.Extensions = append(groupInfo.Extensions, Extension{
			Type: mlsext.ExtensionTypeExternalPub,
			Data: extPubW.Bytes(),
		})
	}

	tbs := groupInfo.MarshalTBS()
	sig, err := ciphersuite.SignWithLabel(signerPrivKey, "GroupInfoTBS", tbs)
	if err != nil {
		return nil, fmt.Errorf("signing group info: %w", err)
	}
	groupInfo.Signature = sig.AsSlice()

	return groupInfo, nil
}

// VerifyPublicMessage verifies a PublicMessage signature and membership tag (RFC 9420 §6.1).
//
// This verifies that the message was sent by a valid group member and
// that the membership tag is correct.
func (g *Group) VerifyPublicMessage(pm *framing.PublicMessage) error {
	if pm == nil {
		return fmt.Errorf("public message is nil")
	}

	switch pm.Content.Sender.Type {
	case framing.SenderTypeMember:
		senderIdx := LeafNodeIndex(pm.Content.Sender.LeafIndex)
		leaf := g.ratchetTree.GetLeaf(treesync.LeafIndex(senderIdx))
		if leaf == nil || leaf.LeafData == nil {
			return fmt.Errorf("missing sender signature key")
		}

		rawKey := leaf.LeafData.SigKeyBytes()
		if len(rawKey) == 0 {
			return fmt.Errorf("missing sender signature key")
		}
		pubKey := ciphersuite.NewMLSSignaturePublicKey(rawKey, g.cipherSuite.SignatureScheme())
		ac := &framing.AuthenticatedContent{
			WireFormat:   framing.WireFormatPublicMessage,
			Content:      pm.Content,
			Auth:         pm.Auth,
			GroupContext: g.groupContext.Marshal(),
		}
		if err := ciphersuite.VerifyWithLabel(pubKey, "FramedContentTBS", ac.MarshalTBS(), pm.Auth.Signature); err != nil {
			return fmt.Errorf("public message signature verification failed: %w", err)
		}

		if g.epochSecrets == nil || g.epochSecrets.MembershipKey == nil {
			return fmt.Errorf("membership_key not available")
		}
		return pm.VerifyMembershipTagWithContext(g.cipherSuite, g.epochSecrets.MembershipKey, g.groupContext.Marshal())
	case framing.SenderTypeExternal:
		// RFC §12.1.8.1: external senders sign with their own key, listed in the
		// ExternalSenders extension (0x0005) of the GroupContext.
		sigKey, err := g.getExternalSenderSigningKey(pm.Content.Sender.SenderIndex)
		if err != nil {
			return fmt.Errorf("external sender: %w", err)
		}
		pubKey := ciphersuite.NewMLSSignaturePublicKey(sigKey, g.cipherSuite.SignatureScheme())
		ac := &framing.AuthenticatedContent{
			WireFormat:   framing.WireFormatPublicMessage,
			Content:      pm.Content,
			Auth:         pm.Auth,
			GroupContext: g.groupContext.Marshal(),
		}
		if err := ciphersuite.VerifyWithLabel(pubKey, "FramedContentTBS", ac.MarshalTBS(), pm.Auth.Signature); err != nil {
			return fmt.Errorf("external public message signature verification failed: %w", err)
		}
		return nil
	case framing.SenderTypeNewMemberProposal:
		return nil
	case framing.SenderTypeNewMemberCommit:
		commitBody, ok := pm.Content.Body.(framing.CommitBody)
		if !ok {
			return fmt.Errorf("new member commit has no commit body")
		}

		commit, err := UnmarshalCommit(commitBody.Data)
		if err != nil {
			return fmt.Errorf("unmarshaling new member commit: %w", err)
		}
		if commit.Path == nil || commit.Path.LeafNode == nil {
			return fmt.Errorf("new member commit missing update path leaf node")
		}

		rawKey := commit.Path.LeafNode.SigKeyBytes()
		if len(rawKey) == 0 {
			return fmt.Errorf("new member commit missing leaf node signature key")
		}

		pubKey := ciphersuite.NewMLSSignaturePublicKey(rawKey, g.cipherSuite.SignatureScheme())
		ac := &framing.AuthenticatedContent{
			WireFormat:   framing.WireFormatPublicMessage,
			Content:      pm.Content,
			Auth:         pm.Auth,
			GroupContext: g.groupContext.Marshal(),
		}
		if err := ciphersuite.VerifyWithLabel(pubKey, "FramedContentTBS", ac.MarshalTBS(), pm.Auth.Signature); err != nil {
			return fmt.Errorf("new member commit signature verification failed: %w", err)
		}
		return nil
	default:
		return nil
	}
}

// getExternalSenderSigningKey returns the signature public key for the external
// sender at senderIndex, as listed in the ExternalSenders extension (0x0005) of
// the GroupContext (RFC 9420 §12.1.8.1).
func (g *Group) getExternalSenderSigningKey(senderIndex uint32) ([]byte, error) {
	const extTypeExternalSenders = 0x0005
	for _, ext := range g.groupContext.Extensions {
		if ext.Type != extTypeExternalSenders {
			continue
		}
		senders, err := parseExternalSenders(ext.Data)
		if err != nil {
			return nil, fmt.Errorf("parsing ExternalSenders extension: %w", err)
		}
		if int(senderIndex) >= len(senders) {
			return nil, fmt.Errorf("sender index %d out of range (have %d external senders)", senderIndex, len(senders))
		}
		return senders[senderIndex].SignatureKey, nil
	}
	return nil, fmt.Errorf("ExternalSenders extension not found in GroupContext")
}

// LoadPsk loads a pre-shared key into the group's PSK cache.
//
// This is used for external PSKs that are referenced in PreSharedKey proposals.
func (g *Group) LoadPsk(pskID, pskBytes []byte) {
	g.pskMu.Lock()
	defer g.pskMu.Unlock()
	if g.cachedPsks == nil {
		g.cachedPsks = make(map[string][]byte)
	}
	g.cachedPsks[string(pskID)] = pskBytes
}

func keyPackageToTreeSyncLifetime(lifetime *keypackages.Lifetime) *treesync.LeafNodeLifetime {
	if lifetime == nil {
		return nil
	}
	return &treesync.LeafNodeLifetime{NotBefore: lifetime.NotBefore, NotAfter: lifetime.NotAfter}
}

func keyPackageExtensionsToTreeSync(exts []keypackages.Extension) [][]byte {
	if len(exts) == 0 {
		return nil
	}
	out := make([][]byte, len(exts))
	for i, ext := range exts {
		w := tls.NewWriter()
		w.WriteUint16(uint16(ext.Type))
		w.WriteVLBytes(ext.Data)
		out[i] = w.Bytes()
	}
	return out
}

func treeSyncToKeyPackageCapabilities(caps *treesync.LeafNodeCapabilities) *keypackages.Capabilities {
	if caps == nil {
		return nil
	}

	versions := make([]keypackages.ProtocolVersion, len(caps.ProtocolVersions))
	for i, v := range caps.ProtocolVersions {
		versions[i] = keypackages.ProtocolVersion(v)
	}

	cipherSuites := make([]keypackages.CipherSuite, len(caps.CipherSuites))
	for i, cs := range caps.CipherSuites {
		cipherSuites[i] = ciphersuite.CipherSuite(cs)
	}

	return &keypackages.Capabilities{
		ProtocolVersions: versions,
		CipherSuites:     cipherSuites,
		Extensions:       append([]uint16(nil), caps.Extensions...),
		Proposals:        append([]uint16(nil), caps.Proposals...),
		Credentials:      append([]uint16(nil), caps.Credentials...),
	}
}

func treeSyncToKeyPackageLifetime(lifetime *treesync.LeafNodeLifetime) *keypackages.Lifetime {
	if lifetime == nil {
		return nil
	}
	return &keypackages.Lifetime{NotBefore: lifetime.NotBefore, NotAfter: lifetime.NotAfter}
}

// sortProposalsByRFCOrder sorts proposals (and their parallel senders slice)
// according to RFC 9420 §12.4.2 application order:
// GroupContextExtensions → Update → Remove → Add → PreSharedKey → ReInit → ExternalInit.
// The sort is stable so proposals of the same type retain their original order.
func sortProposalsByRFCOrder(proposals []*Proposal, senders []LeafNodeIndex) {
	rfcPriority := map[ProposalType]int{
		ProposalTypeGroupContextExtensions: 1,
		ProposalTypeUpdate:                 2,
		ProposalTypeRemove:                 3,
		ProposalTypeAdd:                    4,
		ProposalTypePreSharedKey:           5,
		ProposalTypeReInit:                 6,
		ProposalTypeExternalInit:           7,
	}

	// Build index slice and stable-sort it.
	indices := make([]int, len(proposals))
	for i := range indices {
		indices[i] = i
	}
	sort.SliceStable(indices, func(a, b int) bool {
		pa := rfcPriority[proposals[indices[a]].Type]
		pb := rfcPriority[proposals[indices[b]].Type]
		return pa < pb
	})

	// Reorder in place using the sorted indices.
	sortedP := make([]*Proposal, len(proposals))
	sortedS := make([]LeafNodeIndex, len(senders))
	for i, idx := range indices {
		sortedP[i] = proposals[idx]
		if idx < len(senders) {
			sortedS[i] = senders[idx]
		}
	}
	copy(proposals, sortedP)
	copy(senders, sortedS)
}

func keyPackageLeafToTreeSync(leaf *keypackages.LeafNode) *treesync.LeafNodeData {
	if leaf == nil {
		return nil
	}
	leafData := &treesync.LeafNodeData{
		EncryptionKey:   leaf.EncryptionKey,
		SignatureKey:    leaf.SignatureKey,
		SignatureKeyRaw: append([]byte(nil), leaf.SignatureKeyBytes...),
		Credential:      leaf.Credential,
		Capabilities:    toTreeSyncCapabilities(leaf.Capabilities),
		Lifetime:        keyPackageToTreeSyncLifetime(leaf.Lifetime),
		Extensions:      keyPackageExtensionsToTreeSync(leaf.Extensions),
		LeafNodeSource:  leaf.LeafNodeSource,
		ParentHash:      append([]byte(nil), leaf.ParentHash...),
		Signature:       append([]byte(nil), leaf.Signature...),
	}
	if leafData.Capabilities == nil {
		leafData.Capabilities = &treesync.LeafNodeCapabilities{}
	}
	return leafData
}

// Export derives an external key using MLS Exporter (RFC 9420 §8.5).
// Useful for applications that need to derive session keys (e.g., DAVE media keys).
// The label should be unique for the application. The context may be nil.
//
// Parameters:
//   - label: Exporter label for domain separation
//   - ctx: Context bytes for key derivation (may be nil)
//   - length: Desired key length in bytes
//
// Returns the derived key bytes, or an error if exporter_secret is not available.
func (g *Group) Export(label string, ctx []byte, length int) ([]byte, error) {
	if g.epochSecrets == nil || g.epochSecrets.ExporterSecret == nil {
		return nil, fmt.Errorf("exporter_secret not available")
	}

	if g.state != StateOperational {
		return nil, fmt.Errorf("group not operational")
	}

	// RFC 9420 §8.5 = HKDF-Expand-Label(exporter_secret, label, context, length)
	return schedule.Exporter(g.epochSecrets.ExporterSecret, g.cipherSuite, schedule.ExporterLabel(label), ctx, length)
}
